import { NextResponse } from "next/server";
import type { NextRequest } from "next/server";

export function middleware(_req: NextRequest) {
  return NextResponse.next();
}

export const config = {
  matcher: ["/admin/:path*"],
};

/**
 * 管理后台 - 博客详情 API - 使用新的标准化响应系统
 */

import { initDb } from "@/lib/db-init";
import { getAuthUser } from "@/lib/http";
import { getBlogDetail, updateBlog, deleteBlog } from "@/lib/admin";
import { withErrorHandler, assertAuthenticated, assertAuthorized, assertExists } from "@/middleware/error-handler";
import { successResponse, errorResponses, noContentResponse } from "@/lib/api-response";
import { validateParams, validateBody, z } from "@/lib/validate";
import { isAdminUser } from "@/lib/http";

// 路由参数验证 Schema
const paramsSchema = z.object({
  id: z.coerce.number().int().positive("文章ID必须是正整数"),
});

// 更新博客请求体验证 Schema
const updateBlogSchema = z.object({
  title: z.string().min(1).max(200).optional(),
  content: z.string().min(1).optional(),
  tags: z.string().max(500).optional(),
  status: z.enum(["published", "draft"]).optional(),
  category_id: z.number().optional().nullable(),
}).passthrough(); // 允许其他字段

export const GET = withErrorHandler(async (_: Request, { params }: { params: Promise<{ id: string }> }) => {
  const paramsData = await params;
  initDb();
  
  const user = await getAuthUser();
  assertAuthenticated(user);
  assertAuthorized(isAdminUser(user), "需要管理员权限");
  
  const { id } = validateParams(paramsData, paramsSchema);
  const blog = getBlogDetail(id);
  assertExists(blog, "文章不存在");
  
  return successResponse(blog);
});

export const PUT = withErrorHandler(async (req: Request, { params }: { params: Promise<{ id: string }> }) => {
  const paramsData = await params;
  initDb();
  
  const user = await getAuthUser();
  assertAuthenticated(user);
  assertAuthorized(isAdminUser(user), "需要管理员权限");
  
  const { id } = validateParams(paramsData, paramsSchema);
  const body = await validateBody(req, updateBlogSchema);

  updateBlog(id, {
    ...body,
    category_id: body.category_id ?? undefined,
  });
  
  return successResponse({ updated: true });
});

export const DELETE = withErrorHandler(async (_: Request, { params }: { params: Promise<{ id: string }> }) => {
  const paramsData = await params;
  initDb();
  
  const user = await getAuthUser();
  assertAuthenticated(user);
  assertAuthorized(isAdminUser(user), "需要管理员权限");
  
  const { id } = validateParams(paramsData, paramsSchema);
  deleteBlog(id);
  
  return noContentResponse();
});

/**
 * 管理后台 - 分类管理 API - 使用新的标准化响应系统
 */

import { initDb } from "@/lib/db-init";
import { getAuthUser } from "@/lib/http";
import { createCategory, listCategories } from "@/lib/admin";
import { withErrorHandler, assertAuthenticated, assertAuthorized } from "@/middleware/error-handler";
import { successResponse, errorResponses, paginatedResponse, createdResponse } from "@/lib/api-response";
import { validateQuery, validateBody, z } from "@/lib/validate";
import { isAdminUser } from "@/lib/http";

// 查询参数验证 Schema
const querySchema = z.object({
  page: z.coerce.number().int().min(1).default(1),
  limit: z.coerce.number().int().min(1).max(100).default(100),
  search: z.string().default(""),
});

// 创建分类请求体验证 Schema
const createCategorySchema = z.object({
  name: z.string().min(1, "分类名称不能为空").max(100, "分类名称最多100字"),
  slug: z.string().max(100).optional(),
  description: z.string().max(500).default(""),
  is_active: z.union([z.boolean(), z.number()]).default(1),
});

function slugify(text: string) {
  return String(text || "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9\u4e00-\u9fa5]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

export const GET = withErrorHandler(async (req: Request) => {
  initDb();
  
  const user = await getAuthUser();
  assertAuthenticated(user);
  assertAuthorized(isAdminUser(user), "需要管理员权限");
  
  const { page, limit, search } = await validateQuery(req, querySchema);
  
  const result = listCategories(page, limit, search);
  
  // listCategories 返回 { categories, total, page, limit }
  return paginatedResponse(result.categories, result.total, page ?? 1, limit ?? 100);
});

export const POST = withErrorHandler(async (req: Request) => {
  initDb();
  
  const user = await getAuthUser();
  assertAuthenticated(user);
  assertAuthorized(isAdminUser(user), "需要管理员权限");
  
  const body = await validateBody(req, createCategorySchema);
  
  const slug = body.slug?.trim() || slugify(body.name);
  
  if (!slug) {
    return errorResponses.badRequest("分类别名不能为空");
  }
  
  try {
    const id = createCategory({
      name: body.name.trim(),
      slug,
      description: body.description,
      is_active: body.is_active === 0 || body.is_active === false ? 0 : 1,
    });
    return createdResponse({ id });
  } catch (error: any) {
    if (String(error?.message || "").includes("UNIQUE")) {
      return errorResponses.conflict("分类名称或别名已存在");
    }
    throw error;
  }
});

/**
 * 安全配置管理 API
 * 仅管理员可访问
 * 
 * GET  - 获取安全配置状态
 * POST - 设置敏感配置（加密存储）
 */

import { NextRequest } from "next/server";
import { initDb } from "@/lib/db-init";
import { adminAuthMiddleware, createJsonResponse, createSecurityContext, securityLog } from "@/lib/security-middleware";
import { validateRequestMiddleware } from "@/lib/security-middleware";
import {
  getSecureConfigStatus,
  setSecureConfig,
  getApiKey,
  getApiKeyPreview,
  clearSecureConfigCache,
  SensitiveConfigKey,
} from "@/lib/secure-config";
import { apiConfig, appConfig, getSafeConfig, validateConfig } from "@/lib/config";
import { maskSensitiveValue } from "@/lib/security";

/**
 * GET /api/admin/security
 * 获取安全配置状态
 */
export async function GET(req: NextRequest) {
  initDb();
  
  // 1. 管理员认证
  const user = await adminAuthMiddleware(req);
  if (user instanceof Response) return user;
  
  // 2. 记录访问日志
  const context = await createSecurityContext(req);
  securityLog("admin_security_status_view", context);
  
  // 3. 获取配置验证结果
  const validation = validateConfig();
  
  // 4. 获取安全配置状态
  const secureConfigStatus = getSecureConfigStatus();
  
  // 5. 返回安全响应（敏感信息已掩码）
  return createJsonResponse({
    environment: appConfig.env,
    isProduction: appConfig.isProd,
    
    // 配置验证结果
    validation: {
      valid: validation.valid,
      missing: validation.missing,
      warnings: validation.warnings,
    },
    
    // API 配置状态
    api: {
      sora2: {
        fromEnv: !!apiConfig.sora2.apiKey,
        preview: apiConfig.sora2.apiKey ? maskSensitiveValue(apiConfig.sora2.apiKey) : null,
        baseUrl: apiConfig.sora2.baseUrl,
      },
      grsai: {
        fromEnv: !!apiConfig.grsai.token,
        preview: apiConfig.grsai.token ? maskSensitiveValue(apiConfig.grsai.token) : null,
        hostMode: apiConfig.grsai.hostMode,
      },
    },
    
    // 加密存储的配置
    secureStorage: {
      encryptionEnabled: secureConfigStatus.encryptionEnabled,
      storedConfigs: secureConfigStatus.keys,
    },
    
    // 当前生效的 API 密钥
    effectiveApiKey: getApiKeyPreview(),
    
    // 完整配置快照（已脱敏）
    configSnapshot: getSafeConfig(),
    
    timestamp: new Date().toISOString(),
  });
}

/**
 * POST /api/admin/security
 * 设置敏感配置
 * 
 * 请求体：
 * {
 *   "action": "setConfig",
 *   "key": "api_key" | "token",
 *   "value": "secret-value"
 * }
 * 
 * 或：
 * {
 *   "action": "clearCache"
 * }
 */
export async function POST(req: NextRequest) {
  initDb();
  
  // 1. 管理员认证
  const user = await adminAuthMiddleware(req);
  if (user instanceof Response) return user;
  
  // 2. 解析和验证请求体
  let body: unknown;
  try {
    body = await req.json();
  } catch {
    return createJsonResponse({ error: "Invalid JSON body" }, 400);
  }
  
  const validation = validateRequestMiddleware<{
    action: "setConfig" | "clearCache";
    key?: SensitiveConfigKey;
    value?: string;
  }>(body, {
    action: {
      required: true,
      type: "string",
      pattern: /^(setConfig|clearCache)$/,
    },
    key: {
      required: false,
      type: "string",
    },
    value: {
      required: false,
      type: "string",
    },
  });
  
  if (!validation.valid) {
    return validation.response;
  }
  
  const { action, key, value } = validation.data;
  const context = await createSecurityContext(req);
  
  // 3. 执行操作
  if (action === "setConfig") {
    if (!key || !value) {
      return createJsonResponse(
        { error: "Missing key or value" },
        400
      );
    }
    
    // 验证 key
    const validKeys: SensitiveConfigKey[] = ["api_key", "token", "webhook_secret", "oauth_client_secret"];
    if (!validKeys.includes(key)) {
      return createJsonResponse(
        { error: "Invalid config key", validKeys },
        400
      );
    }
    
    try {
      setSecureConfig(key, value);
      
      securityLog("admin_security_config_set", context, { 
        key, 
        admin: user,
        source: "api",
      });
      
      // 警告：推荐使用环境变量
      const warning = 
        "Config stored in database. For production use, it is recommended to set " +
        (key === "api_key" ? "SORA2_API_KEY" : "GRSAI_TOKEN") +
        " environment variable instead.";
      
      return createJsonResponse({
        success: true,
        message: "Configuration saved securely",
        warning,
        preview: maskSensitiveValue(value),
        timestamp: new Date().toISOString(),
      });
    } catch (error) {
      console.error("[Security] Failed to save config:", error);
      return createJsonResponse(
        { error: "Failed to save configuration" },
        500
      );
    }
  }
  
  if (action === "clearCache") {
    clearSecureConfigCache();
    
    securityLog("admin_security_cache_cleared", context, { admin: user });
    
    return createJsonResponse({
      success: true,
      message: "Configuration cache cleared",
      timestamp: new Date().toISOString(),
    });
  }
  
  return createJsonResponse({ error: "Invalid action" }, 400);
}

/**
 * 使用示例：
 * 
 * 1. 查看安全配置状态：
 * GET /api/admin/security
 * Authorization: Bearer <admin-token>
 * 
 * 2. 设置 API 密钥：
 * POST /api/admin/security
 * Authorization: Bearer <admin-token>
 * Content-Type: application/json
 * 
 * {
 *   "action": "setConfig",
 *   "key": "api_key",
 *   "value": "sk-xxxxxx"
 * }
 * 
 * 3. 清除配置缓存：
 * POST /api/admin/security
 * Authorization: Bearer <admin-token>
 * Content-Type: application/json
 * 
 * {
 *   "action": "clearCache"
 * }
 */

/**
 * 文章评论 API - 使用新的标准化响应系统
 */

import { initDb } from "@/lib/db-init";
import { getAuthUser } from "@/lib/http";
import { listComments, addComment } from "@/lib/blog";
import { withErrorHandler } from "@/middleware/error-handler";
import { successResponse, errorResponses, createdResponse } from "@/lib/api-response";
import { validateBody, z } from "@/lib/validate";

// 评论列表查询参数验证
const querySchema = z.object({
  page: z.coerce.number().int().min(1).default(1),
  size: z.coerce.number().int().min(1).max(100).default(50),
});

// 创建评论请求体验证
const createCommentSchema = z.object({
  content: z.string().min(1, "评论内容不能为空").max(2000, "评论最多2000字"),
  author: z.string().max(50, "作者名称最多50字").optional(),
  parent_id: z.union([z.number(), z.string()]).optional().nullable(),
});

/**
 * 获取文章评论列表
 * GET /api/blog/[slug]/comments
 */
export const GET = withErrorHandler(async (req, { params }) => {
  const paramsData = await params;
  initDb();
  
  const { slug } = paramsData;
  
  // 解析查询参数
  const { searchParams } = new URL(req.url);
  const query = querySchema.parse({
    page: searchParams.get("page") || "1",
    size: searchParams.get("size") || "50",
  });
  
  const comments = listComments(slug);
  
  return successResponse(comments);
});

/**
 * 发表评论
 * POST /api/blog/[slug]/comments
 */
export const POST = withErrorHandler(async (req, { params }) => {
  const paramsData = await params;
  initDb();
  
  const { slug } = paramsData;
  
  // 验证请求体
  const body = await validateBody(req, createCommentSchema);
  
  // 获取当前用户（可选）
  const user = await getAuthUser();
  const author = user || body.author || "访客";
  
  // 获取客户端 IP
  const ip = req.headers.get("x-forwarded-for") || "";
  
  // 处理 parent_id
  const parentId = body.parent_id 
    ? (typeof body.parent_id === 'string' ? parseInt(body.parent_id, 10) : body.parent_id)
    : null;
  
  // 添加评论
  const result = addComment(slug, author, body.content.trim(), parentId, ip);
  
  if (!result.ok) {
    return errorResponses.notFound("文章不存在");
  }
  
  return createdResponse({ ok: true });
});

/**
 * 获取粉丝列表 API - 使用新的标准化响应系统
 */

import { NextRequest } from "next/server";
import { initDb } from "@/lib/db-init";
import { getAuthUser } from "@/lib/http";
import { listFollowers } from "@/lib/follow";
import { withErrorHandler } from "@/middleware/error-handler";
import { successResponse, errorResponses, paginatedResponse } from "@/lib/api-response";
import { validateQuery, z } from "@/lib/validate";

// 查询参数验证 Schema
const querySchema = z.object({
  username: z.string().optional(),
  page: z.coerce.number().int().min(1).default(1),
  size: z.coerce.number().int().min(1).max(100).default(20),
  q: z.string().optional().default(""),
});

export const GET = withErrorHandler(async (req: NextRequest) => {
  // 初始化数据库
  initDb();

  // 验证用户认证
  const user = await getAuthUser();
  if (!user) {
    return errorResponses.unauthorized("请先登录");
  }

  // 验证查询参数
  const { username, page, size, q } = await validateQuery(req, querySchema);

  // 获取目标用户名（默认为当前用户）
  const targetUsername = username || user;

  // 获取粉丝列表
  const result = listFollowers(targetUsername, page, size, q);

  return successResponse(result);
});

