/**
 * 获取未读消息总数 API - 使用新的标准化响应系统
 */

import { NextRequest } from "next/server";
import { getUnreadTotal } from "@/lib/messages";
import { getUnreadNotificationCount } from "@/lib/blog";
import { getAuthUser } from "@/lib/http";
import { withErrorHandler } from "@/middleware/error-handler";
import { successResponse } from "@/lib/api-response";

export const GET = withErrorHandler(async (req: NextRequest) => {
  // 未认证用户返回 0（用于徽章显示，静默处理）
  const user = await getAuthUser();
  if (!user) {
    return successResponse({ unread_count: 0 });
  }

  try {
    const msgTotal = getUnreadTotal(user);
    const notifTotal = getUnreadNotificationCount(user);
    return successResponse({ unread_count: msgTotal + notifTotal });
  } catch {
    // 出错时返回 0，不影响前端徽章显示
    return successResponse({ unread_count: 0 });
  }
});

/**
 * 安全 API 路由示例
 * 演示如何使用安全中间件和验证功能
 * 
 * 实际使用时可作为模板参考
 */

import { NextRequest } from "next/server";
import {
  createJsonResponse,
  rateLimitMiddleware,
  validateRequestMiddleware,
  authMiddleware,
  createSecurityContext,
  securityLog,
} from "@/lib/security-middleware";
import { detectSqlInjection, isValidUsername, validatePassword } from "@/lib/security";

/**
 * GET 请求示例 - 带速率限制
 */
export async function GET(req: NextRequest) {
  // 1. 速率限制检查
  const rateLimitResult = rateLimitMiddleware(req);
  if (rateLimitResult) return rateLimitResult;
  
  // 2. 获取安全上下文（用于日志）
  const context = await createSecurityContext(req);
  securityLog("secure_example_access", context);
  
  // 3. 获取查询参数
  const { searchParams } = new URL(req.url);
  const page = parseInt(searchParams.get("page") || "1", 10);
  const limit = parseInt(searchParams.get("limit") || "20", 10);
  
  // 4. 验证分页参数
  if (isNaN(page) || page < 1 || isNaN(limit) || limit < 1 || limit > 100) {
    return createJsonResponse(
      { error: "Invalid pagination parameters" },
      400
    );
  }
  
  // 5. 返回安全响应
  return createJsonResponse({
    message: "Secure API response",
    data: { page, limit },
    timestamp: new Date().toISOString(),
  });
}

/**
 * POST 请求示例 - 带认证和请求体验证
 */
export async function POST(req: NextRequest) {
  // 1. 速率限制检查
  const rateLimitResult = rateLimitMiddleware(req);
  if (rateLimitResult) return rateLimitResult;
  
  // 2. 认证检查（如果需要）
  // const user = await authMiddleware(req);
  // if (user instanceof Response) return user;
  
  // 3. 解析请求体
  let body: unknown;
  try {
    body = await req.json();
  } catch {
    return createJsonResponse(
      { error: "Invalid JSON body" },
      400
    );
  }
  
  // 4. 验证请求体
  const validation = validateRequestMiddleware<{
    action: string;
    username: string;
    password?: string;
    query?: string;
  }>(body, {
    action: {
      required: true,
      type: "string",
      pattern: /^(create|update|delete|search)$/,
    },
    username: {
      required: true,
      type: "string",
      minLength: 3,
      maxLength: 30,
      validator: (value) => {
        if (!isValidUsername(value)) {
          return "Username must be 3-30 characters, alphanumeric with underscores and hyphens only";
        }
        return true;
      },
    },
    password: {
      required: false,
      type: "string",
      validator: (value) => {
        if (!value) return true; // 可选字段
        const result = validatePassword(value);
        if (!result.valid) {
          return result.errors.join("; ");
        }
        return true;
      },
    },
    query: {
      required: false,
      type: "string",
      maxLength: 200,
    },
  });
  
  if (!validation.valid) {
    return validation.response;
  }
  
  const { action, username, password, query } = validation.data;
  
  // 5. SQL 注入检查（对查询参数）
  if (query && detectSqlInjection(query)) {
    const context = await createSecurityContext(req);
    securityLog("sql_injection_detected", context, { query, action });
    
    return createJsonResponse(
      { error: "Invalid query parameter" },
      400
    );
  }
  
  // 6. 获取安全上下文并记录
  const context = await createSecurityContext(req);
  securityLog("secure_example_action", context, { 
    action, 
    username,
    hasPassword: !!password,
    hasQuery: !!query,
  });
  
  // 7. 返回安全响应
  return createJsonResponse({
    success: true,
    message: "Action processed securely",
    data: {
      action,
      username,
      // 永远不要返回密码！
      query: query ? `${query.substring(0, 20)}...` : undefined,
    },
    timestamp: new Date().toISOString(),
  });
}

/**
 * 使用示例：
 * 
 * GET /api/secure-example?page=1&limit=20
 * 
 * POST /api/secure-example
 * Content-Type: application/json
 * 
 * {
 *   "action": "search",
 *   "username": "john_doe",
 *   "query": "example search"
 * }
 */

/**
 * 访问记录 API - 使用新的标准化响应系统
 */

import { getBlogDb } from "@/lib/db";
import { headers } from "next/headers";
import { withErrorHandler } from "@/middleware/error-handler";
import { successResponse, errorResponses } from "@/lib/api-response";
import { validateBody, z } from "@/lib/validate";

// 请求体验证 Schema
const trackVisitSchema = z.object({
  visitorId: z.string().min(1, "Visitor ID 不能为空"),
  pageUrl: z.string().default("/"),
});

export const POST = withErrorHandler(async (request: Request) => {
  const db = getBlogDb();
  
  // 验证请求体
  const { visitorId, pageUrl } = await validateBody(request, trackVisitSchema);

  const headersList = await headers();
  const userAgent = headersList.get("user-agent") || "";
  const ipAddress = headersList.get("x-forwarded-for") || headersList.get("x-real-ip") || "unknown";

  // Record the visit
  db.prepare(`
    INSERT INTO site_visits (visitor_id, page_url, user_agent, ip_address)
    VALUES (?, ?, ?, ?)
  `).run(visitorId, pageUrl, userAgent, ipAddress);

  // Update or create unique visitor record
  const existingVisitor = db.prepare(`
    SELECT visitor_id FROM unique_visitors WHERE visitor_id = ?
  `).get(visitorId);

  if (existingVisitor) {
    db.prepare(`
      UPDATE unique_visitors 
      SET last_visit = CURRENT_TIMESTAMP, visit_count = visit_count + 1
      WHERE visitor_id = ?
    `).run(visitorId);
  } else {
    db.prepare(`
      INSERT INTO unique_visitors (visitor_id)
      VALUES (?)
    `).run(visitorId);
  }

  return successResponse({ recorded: true });
});

/**
 * 文件上传 API - 使用新的标准化响应系统
 */

import { initDb } from "@/lib/db-init";
import { getAuthUser } from "@/lib/http";
import path from "path";
import fs from "fs/promises";
import { withErrorHandler, assertAuthenticated } from "@/middleware/error-handler";
import { successResponse, errorResponses, createdResponse } from "@/lib/api-response";

export const POST = withErrorHandler(async (req: Request) => {
  initDb();
  
  const user = await getAuthUser();
  assertAuthenticated(user, "请先登录");
  
  const form = await req.formData();
  const file = form.get("file") as File | null;
  
  if (!file) {
    return errorResponses.badRequest("缺少文件");
  }
  
  if (!file.type.startsWith("image/")) {
    return errorResponses.badRequest("仅允许上传图片文件");
  }
  
  const arrayBuffer = await file.arrayBuffer();
  const buffer = Buffer.from(arrayBuffer);
  const safeName = file.name.replace(/[^a-zA-Z0-9_.-]/g, "");
  const ext = path.extname(safeName) || ".png";
  const name = `${Date.now()}-${Math.random().toString(16).slice(2)}${ext}`;
  
  // Keep upload path aligned with /uploads/[...path] route.ts
  const targetDir = path.resolve(process.cwd(), "..", "uploads");
  await fs.mkdir(targetDir, { recursive: true });
  await fs.writeFile(path.join(targetDir, name), buffer);
  
  return createdResponse({ url: `/uploads/${name}` });
});

/**
 * 视频任务详情 API - 使用新的标准化响应系统
 */

import { NextRequest } from "next/server";
import { initDb } from "@/lib/db-init";
import { getAuthUser } from "@/lib/http";
import { getTask, pollAndUpdate } from "@/lib/video";
import { withErrorHandler, assertAuthenticated, assertExists } from "@/middleware/error-handler";
import { successResponse, errorResponses } from "@/lib/api-response";
import { validateParams, z } from "@/lib/validate";

// 定义路由参数验证 Schema
const paramsSchema = z.object({
  id: z.string().min(1, "任务ID不能为空"),
});

export const GET = withErrorHandler(async (req: NextRequest, { params }: { params: Promise<{ id: string }> }) => {
  // 初始化数据库
  initDb();

  // 获取当前用户
  const user = await getAuthUser();
  assertAuthenticated(user, "请先登录");

  // 验证路由参数
  const { id } = validateParams(await params, paramsSchema);

  // 获取任务
  let task = getTask(id, user);
  assertExists(task, "任务不存在");

  // 如果任务正在执行中，尝试更新状态
  if (task.status === "pending" || task.status === "running") {
    try {
      await pollAndUpdate(id);
      task = getTask(id, user);
    } catch {
      // 忽略轮询错误，返回已获取的任务
    }
  }

  return successResponse(task);
});

"use client";

import { useEffect, useState } from "react";
import Link from "next/link";

interface FriendLink {
  id: number;
  name: string;
  url: string;
  description: string | null;
  avatar_url: string | null;
  sort_order: number;
}

export default function FriendsPage() {
  const [links, setLinks] = useState<FriendLink[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch("/api/friend-links")
      .then((res) => res.json())
      .then((data) => {
        setLinks(data.links || []);
        setLoading(false);
      })
      .catch((error) => {
        console.error("Failed to fetch friend links:", error);
        setLoading(false);
      });
  }, []);

  const getFallbackIcon = (siteUrl: string) => {
    try {
      return `${new URL(siteUrl).origin}/favicon.ico`;
    } catch {
      return "";
    }
  };

  if (loading) {
    return (
      <div className="container py-8">
        <div className="text-center text-muted">加载中...</div>
      </div>
    );
  }

  return (
    <div className="container py-8">
      <div className="mb-8">
        <h1 className="text-3xl font-bold mb-2">友情链接</h1>
        <p className="text-muted">这里收录了一些优秀的博客和网站</p>
      </div>

      {links.length === 0 ? (
        <div className="text-center text-muted py-12">
          暂无友情链接
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {links.map((link) => (
            <a
              key={link.id}
              href={link.url}
              target="_blank"
              rel="noopener noreferrer"
              className="card hover:border-blue-500/50 transition-all duration-200 hover:shadow-lg hover:shadow-blue-500/10"
            >
              <div className="flex items-start gap-4">
                {link.avatar_url || getFallbackIcon(link.url) ? (
                  <img
                    src={link.avatar_url || getFallbackIcon(link.url)}
                    alt={link.name}
                    className="w-16 h-16 rounded-full object-cover flex-shrink-0"
                    onError={(e) => {
                      const fallback = getFallbackIcon(link.url);
                      if (fallback && (e.currentTarget as HTMLImageElement).src !== fallback) {
                        (e.currentTarget as HTMLImageElement).src = fallback;
                        return;
                      }
                      (e.currentTarget as HTMLImageElement).style.display = "none";
                    }}
                  />
                ) : (
                  <div className="w-16 h-16 rounded-full bg-gradient-to-br from-blue-500 to-purple-500 flex items-center justify-center text-white text-xl font-bold flex-shrink-0">
                    {link.name[0]?.toUpperCase()}
                  </div>
                )}
                <div className="flex-1 min-w-0">
                  <h3 className="font-semibold text-lg mb-1 truncate">
                    {link.name}
                  </h3>
                  {link.description && (
                    <p className="text-sm text-muted line-clamp-2">
                      {link.description}
                    </p>
                  )}
                  <p className="text-xs text-blue-400 mt-2 truncate">
                    {link.url}
                  </p>
                </div>
              </div>
            </a>
          ))}
        </div>
      )}
    </div>
  );
}

