﻿"use client";

import { useEffect, useRef, useState } from "react";
import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";
import { useAuth } from "@/app/providers";
import { getThumbnailUrl } from "@/utils/url";
import Footer from "./Footer";
import VisitTracker from "./VisitTracker";

const adminUsername = process.env.NEXT_PUBLIC_ADMIN_USERNAME || "witw";

export default function LegacyLayout({ children }: { children: React.ReactNode }) {
  const { user, logout, updateProfile, isAuthenticated, token } = useAuth();
  const router = useRouter();
  const pathname = usePathname();
  const [showUserMenu, setShowUserMenu] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [unreadCount, setUnreadCount] = useState(0);
  const userMenuRef = useRef<HTMLDivElement | null>(null);
  const isStudio = pathname.startsWith("/studio");

  const toggleUserMenu = async () => {
    const nextState = !showUserMenu;
    setShowUserMenu(nextState);
    if (nextState && isAuthenticated && token) {
      try {
        const res = await fetch("/api/profile", {
          headers: { Authorization: `Bearer ${token}` }
        });
        const data = await res.json();
        if (data.data?.profile) {
          updateProfile(data.data.profile);
        }
      } catch (err) { }
    }
  };

  const toggleMobileMenu = () => setIsMobileMenuOpen(!isMobileMenuOpen);
  const closeMobileMenu = () => setIsMobileMenuOpen(false);

  const handleLogout = () => {
    logout();
    router.push("/login");
    setShowUserMenu(false);
  };

  useEffect(() => {
    function handleOutsideClick(event: MouseEvent) {
      if (!showUserMenu) return;
      if (userMenuRef.current && !userMenuRef.current.contains(event.target as Node)) {
        setShowUserMenu(false);
      }
    }
    document.addEventListener("mousedown", handleOutsideClick);
    return () => document.removeEventListener("mousedown", handleOutsideClick);
  }, [showUserMenu]);

  useEffect(() => {
    if (!isAuthenticated) return;
    const fetchUnread = async () => {
      try {
        const res = await fetch("/api/messages/unread");
        const data = await res.json();
        setUnreadCount(data.unread_count || 0);
      } catch (err) { }
    };
    fetchUnread();
    const interval = setInterval(fetchUnread, 30000);
    return () => clearInterval(interval);
  }, [isAuthenticated]);

  const navClass = (path: string) =>
    pathname === path || (path === "/studio" && isStudio)
      ? "nav-link active"
      : "nav-link";

  return (
    <div className="layout">
      <VisitTracker />
      <header className="header">
        <div className="container header-content">
          <Link href="/" className="brand">witweb</Link>

          <button className="mobile-menu-toggle" onClick={toggleMobileMenu} aria-label="Toggle navigation">
            <span className={`hamburger ${isMobileMenuOpen ? "active" : ""}`}></span>
          </button>

          <nav className={`nav ${isMobileMenuOpen ? "mobile-open" : ""}`}>
            <Link href="/" className={navClass("/")} onClick={closeMobileMenu}>首页</Link>
            <Link href="/categories" className={navClass("/categories")} onClick={closeMobileMenu}>分类</Link>

            {isAuthenticated && user?.username === adminUsername && (
              <Link href="/admin" className="nav-link" onClick={closeMobileMenu}>管理后台</Link>
            )}
            <Link href="/studio" className={navClass("/studio")} onClick={closeMobileMenu}>工作台</Link>
            <Link href="/friends" className={navClass("/friends")} onClick={closeMobileMenu}>友链</Link>
            {isAuthenticated && (
              <Link href="/publish" className={navClass("/publish")} onClick={closeMobileMenu}>发布文章</Link>
            )}
          </nav>

          {isMobileMenuOpen && (
            <div className="mobile-menu-overlay" onClick={closeMobileMenu}></div>
          )}

          <div className="actions">
            {isAuthenticated ? (
              <>
                <div className="header-message-link">
                  <Link href="/messages" className={`nav-link ${pathname === "/messages" ? "active" : ""}`}>
                    消息
                    {unreadCount > 0 && (
                      <span className="unread-badge">{unreadCount > 99 ? "99+" : unreadCount}</span>
                    )}
                  </Link>
                </div>
                <div className="user-menu-container" ref={userMenuRef}>
                  <button className="user-button" onClick={toggleUserMenu}>
                    {user?.avatar_url ? (
                      <img
                        src={getThumbnailUrl(user.avatar_url, 64)}
                        alt={user.nickname || user.username}
                        className="user-avatar"
                      />
                    ) : (
                      <div className="user-avatar-fallback">
                        {(user?.nickname || user?.username)?.[0]?.toUpperCase()}
                      </div>
                    )}
                    <span className="user-name">{user?.nickname || user?.username}</span>
                    <svg className="dropdown-icon" width="12" height="12" viewBox="0 0 12 12" fill="currentColor">
                      <path d="M6 8L2 4h8L6 8z" />
                    </svg>
                  </button>

                  {showUserMenu && (
                    <div className="user-dropdown-card">
                      <div className="user-dropdown-cover"></div>
                      <div className="user-dropdown-body">
                        <div className="user-dropdown-avatar">
                          {user?.avatar_url ? (
                            <img
                              src={getThumbnailUrl(user.avatar_url, 96)}
                              alt={user.nickname || user.username}
                            />
                          ) : (
                            <div className="user-dropdown-avatar-fallback">
                              {(user?.nickname || user?.username)?.[0]?.toUpperCase()}
                            </div>
                          )}
                        </div>
                        <div className="user-dropdown-name">{user?.nickname || user?.username}</div>
                        <div className="user-dropdown-handle">@{user?.username || "user"}</div>
                        <div className="user-dropdown-stats">
                          <Link href="/following" className="user-stat hover:bg-white/5 transition-colors cursor-pointer rounded-md py-1" onClick={() => setShowUserMenu(false)}>
                            <div className="user-stat-value">{user?.following_count ?? 0}</div>
                            <div className="user-stat-label">{"关注"}</div>
                          </Link>
                          <Link href="/followers" className="user-stat hover:bg-white/5 transition-colors cursor-pointer rounded-md py-1" onClick={() => setShowUserMenu(false)}>
                            <div className="user-stat-value">{user?.follower_count ?? 0}</div>
                            <div className="user-stat-label">{"粉丝"}</div>
                          </Link>
                          <Link href="/profile?tab=activity" className="user-stat hover:bg-white/5 transition-colors cursor-pointer rounded-md py-1" onClick={() => setShowUserMenu(false)}>
                            <div className="user-stat-value">{user?.activity_count ?? user?.post_count ?? 0}</div>
                            <div className="user-stat-label">{"动态"}</div>
                          </Link>
                        </div>
                        <div className="user-dropdown-links">
                          <Link href="/profile" className="dropdown-item" onClick={() => setShowUserMenu(false)}>
                            {"\u4e2a\u4eba\u4e2d\u5fc3"}
                          </Link>
                          <Link href="/favorites" className="dropdown-item" onClick={() => setShowUserMenu(false)}>
                            {"\u6211\u7684\u6536\u85cf"}
                          </Link>
                          <button onClick={handleLogout} className="dropdown-item danger">{"\u9000\u51fa\u767b\u5f55"}</button>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              </>
            ) : (
              <div className="auth-buttons">
                <Link href="/login" className="btn-ghost">{"登录"}</Link>
                <Link href="/register" className="btn-primary">{"注册"}</Link>
              </div>
            )}
          </div>
        </div>
      </header>

      <main className={`main-content ${isStudio ? "full-width" : "container"}`}>
        {children}
      </main>

      <Footer />
    </div>
  );
}

"use client";

import Link from "next/link";
import { useRouter } from "next/navigation";
import { ThumbsUpIcon, ThumbsDownIcon, BookmarkIcon, MessageCircleIcon } from "@/components/Icons";
import { getThumbnailUrl } from "@/utils/url";

type PostCardProps = {
  post: any;
  token?: string | null;
  onUpdate?: (updatedPost: any) => void;
  highlight?: string;
};

export default function PostCard({ post, token, onUpdate, highlight = "" }: PostCardProps) {
  const router = useRouter();
  const titleText = post.title || "";
  const rawPreview = (post.content || "").replace(/\s+/g, " ").trim();
  const preview =
    rawPreview.length > 0
      ? `${rawPreview.slice(0, 160)}${rawPreview.length > 160 ? "..." : ""}`
      : "暂无预览";
  const tagList = (post.tags || "")
    .split(/[,，]/)
    .map((tag: string) => tag.trim())
    .filter(Boolean);
  const normalizedQuery = highlight.trim().toLowerCase();
  const matchIndex = normalizedQuery
    ? titleText.toLowerCase().indexOf(normalizedQuery)
    : -1;
  const firstImageMatch = (post.content || "").match(/!\[.*?\]\((.*?)\)|<img.*?src=["'](.*?)["']/);
  const firstImageUrl = firstImageMatch ? (firstImageMatch[1] || firstImageMatch[2]) : null;
  // const thumbnailUrl = getThumbnailUrl(firstImageUrl, 400); // Unused currently in list view but logic existed
  const postAvatar = post.author_avatar || "";
  const avatarUrl = getThumbnailUrl(postAvatar, 64);

  return (
    <div className="card block no-underline text-inherit h-full flex flex-col">
      <Link href={`/post/${post.slug}`} className="block no-underline text-inherit flex-1">
        <div className="card-head flex justify-between items-start mb-3">
          <div className="author flex items-center gap-2">
            {postAvatar ? (
              <img
                src={avatarUrl}
                alt={post.author_name}
                loading="lazy"
                decoding="async"
                className="w-6 h-6 rounded-full"
              />
            ) : (
              <div className="avatar-fallback w-6 h-6 text-xs">{post.author_name?.[0] || "U"}</div>
            )}
            <span className="text-sm font-medium">{post.author_name || post.author || "匿名"}</span>
          </div>
          <span className="text-xs text-muted">{new Date(post.created_at).toLocaleString()}</span>
        </div>

        <h2 className="text-xl font-bold mb-3 leading-tight">
          {matchIndex >= 0 ? (
            <>
              {titleText.slice(0, matchIndex)}
              <span className="highlight">
                {titleText.slice(matchIndex, matchIndex + normalizedQuery.length)}
              </span>
              {titleText.slice(matchIndex + normalizedQuery.length)}
            </>
          ) : (
            titleText
          )}
        </h2>

        <p className="excerpt text-muted text-sm mb-6 line-clamp-2 leading-relaxed">
          {preview}
        </p>
      </Link>

      <div className="post-card-footer flex justify-between items-center mt-auto pt-4 border-t border-white/5">
        <div className="tag-list">
          {tagList.map((tag: string) => (
            <span key={tag} className="tag-pill">#{tag}</span>
          ))}
        </div>

        <div className="post-card-actions flex gap-1">
          <button
            className="btn-ghost btn-sm"
            type="button"
            onClick={(event) => {
              event.preventDefault();
              event.stopPropagation();
              if (!token) {
                router.push("/login");
                return;
              }
              fetch(`/api/blog/${post.slug}/like`, {
                method: "POST",
                headers: { Authorization: `Bearer ${token}` },
              })
                .then((res) => res.json())
                .then((data) => {
                  if (!data) return;
                  onUpdate?.({
                    ...post,
                    like_count: data.like_count ?? post.like_count,
                    dislike_count: data.dislike_count ?? post.dislike_count,
                    comment_count: data.comment_count ?? post.comment_count,
                    favorite_count: data.favorite_count ?? post.favorite_count,
                  });
                })
                .catch(() => { });
            }}
          >
            <ThumbsUpIcon className="inline" /> {post.like_count ?? 0}
          </button>
          <button
            className="btn-ghost btn-sm"
            type="button"
            onClick={(event) => {
              event.preventDefault();
              event.stopPropagation();
              if (!token) {
                router.push("/login");
                return;
              }
              fetch(`/api/blog/${post.slug}/dislike`, {
                method: "POST",
                headers: { Authorization: `Bearer ${token}` },
              })
                .then((res) => res.json())
                .then((data) => {
                  if (!data) return;
                  onUpdate?.({
                    ...post,
                    like_count: data.like_count ?? post.like_count,
                    dislike_count: data.dislike_count ?? post.dislike_count,
                    comment_count: data.comment_count ?? post.comment_count,
                    favorite_count: data.favorite_count ?? post.favorite_count,
                  });
                })
                .catch(() => { });
            }}
          >
            <ThumbsDownIcon className="inline" /> {post.dislike_count ?? 0}
          </button>
          <button
            className={`btn-ghost btn-sm ${post.favorited_by_me ? "text-accent" : ""}`}
            type="button"
            onClick={(event) => {
              event.preventDefault();
              event.stopPropagation();
              if (!token) {
                router.push("/login");
                return;
              }
              fetch(`/api/blog/${post.slug}/favorite`, {
                method: "POST",
                headers: { Authorization: `Bearer ${token}` },
              })
                .then((res) => res.json())
                .then((data) => {
                  if (!data) return;
                  onUpdate?.({
                    ...post,
                    like_count: data.like_count ?? post.like_count,
                    dislike_count: data.dislike_count ?? post.dislike_count,
                    comment_count: data.comment_count ?? post.comment_count,
                    favorite_count: data.favorite_count ?? post.favorite_count,
                    favorited_by_me: data.favorited ?? post.favorited_by_me,
                  });
                })
                .catch(() => { });
            }}
          >
            <BookmarkIcon filled={post.favorited_by_me} className="inline" /> {post.favorite_count ?? 0}
          </button>
          <button
            className="btn-ghost btn-sm"
            type="button"
            onClick={(event) => {
              event.preventDefault();
              event.stopPropagation();
              router.push(`/post/${post.slug}#comments`);
            }}
          >
            <MessageCircleIcon className="inline" /> {post.comment_count ?? 0}
          </button>
        </div>
      </div>
    </div>
  );
}

﻿"use client";

import { useEffect, useState } from "react";

export default function BlogManagementPage() {
  const [blogs, setBlogs] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [page, setPage] = useState(1);
  const [total, setTotal] = useState(0);
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState("");
  const [editingBlog, setEditingBlog] = useState<any>(null);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editLoading, setEditLoading] = useState(false);
  const [categories, setCategories] = useState<any[]>([]);

  useEffect(() => {
    loadBlogs();
  }, [page, search, statusFilter]);

  useEffect(() => {
    if (typeof window === "undefined") return;
    const handler = () => loadBlogs();
    window.addEventListener("profile-updated", handler as EventListener);
    return () => window.removeEventListener("profile-updated", handler as EventListener);
  }, [page, search, statusFilter]);

  useEffect(() => {
    loadCategories();
  }, []);

  const loadBlogs = async () => {
    try {
      setLoading(true);
      const token = localStorage.getItem("token");
      const params = new URLSearchParams({
        page: page.toString(),
        limit: "20",
        ...(search ? { search } : {}),
        ...(statusFilter ? { status: statusFilter } : {}),
      });

      const response = await fetch(`/api/admin/blogs?${params.toString()}`, {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });

      if (response.ok) {
        const data = await response.json();
        setBlogs(data.data?.items || []);
        setTotal(data.data?.total || 0);
      }
    } catch (error) {
      console.error("Failed to load blogs:", error);
    } finally {
      setLoading(false);
    }
  };

  const loadCategories = async () => {
    try {
      const token = localStorage.getItem("token");
      const response = await fetch("/api/admin/categories?limit=200", {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });
      if (response.ok) {
        const data = await response.json();
        setCategories(data.data?.categories || []);
      }
    } catch (error) {
      setCategories([]);
    }
  };

  const handleEdit = async (blogId: number) => {
    try {
      setEditLoading(true);
      const token = localStorage.getItem("token");
      const response = await fetch(`/api/admin/blogs/${blogId}`, {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });

      const data = await response.json();
      if (data.success) {
        setEditingBlog(data.data);
        setIsEditModalOpen(true);
      } else {
        alert(data.error?.message || "获取文章详情失败");
      }
    } catch (error) {
      console.error("Failed to fetch blog detail:", error);
    } finally {
      setEditLoading(false);
    }
  };

  const handleSaveEdit = async () => {
    if (!editingBlog) return;

    try {
      setEditLoading(true);
      const token = localStorage.getItem("token");
      const response = await fetch(`/api/admin/blogs/${editingBlog.id}`, {
        method: "PUT",
        headers: {
          Authorization: `Bearer ${token}`,
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          title: editingBlog.title,
          content: editingBlog.content,
          tags: editingBlog.tags,
          category_id: editingBlog.category_id || null,
        }),
      });

      const data = await response.json();
      if (data.success) {
        alert("更新成功");
        setIsEditModalOpen(false);
        loadBlogs();
      } else {
        alert(data.error?.message || "更新失败");
      }
    } catch (error) {
      console.error("Failed to update blog:", error);
      alert("更新失败");
    } finally {
      setEditLoading(false);
    }
  };

  const handleDelete = async (blogId: number, title: string) => {
    if (!confirm(`确定要删除文章《${title}》吗？此操作不可恢复。`)) {
      return;
    }

    try {
      const token = localStorage.getItem("token");
      const response = await fetch(`/api/admin/blogs/${blogId}`, {
        method: "DELETE",
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });

      const data = await response.json();
      if (data.success) {
        alert("文章删除成功");
        loadBlogs();
      } else {
        alert(data.error?.message || "删除失败");
      }
    } catch (error: any) {
      alert(`删除失败: ${error.message}`);
    }
  };

  const handleStatusChange = async (blogId: number, newStatus: string) => {
    try {
      const token = localStorage.getItem("token");
      const response = await fetch(`/api/admin/blogs/${blogId}`, {
        method: "PUT",
        headers: {
          Authorization: `Bearer ${token}`,
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ status: newStatus }),
      });

      const data = await response.json();
      if (data.success) {
        alert("状态更新成功");
        loadBlogs();
      } else {
        alert(data.error?.message || "更新失败");
      }
    } catch (error: any) {
      alert(`更新失败: ${error.message}`);
    }
  };

  return (
    <div>
      <div className="page-header">
        <h1 className="page-title">文章管理</h1>
        <p className="page-subtitle">管理所有用户文章</p>
      </div>

      <div className="admin-card">
        <div className="card-header" style={{ flexWrap: "wrap", gap: "1rem" }}>
          <input
            type="text"
            placeholder="搜索文章..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="admin-input"
            style={{ width: "300px" }}
          />
          <select
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
            className="admin-select"
          >
            <option value="">全部状态</option>
            <option value="published">已发布</option>
            <option value="draft">草稿</option>
          </select>
          <div style={{ marginLeft: "auto" }}>共 {total} 篇文章</div>
        </div>

        {loading ? null : (
          <table className="admin-table">
            <thead>
              <tr>
                <th>标题</th>
                <th>作者</th>
                <th>分类</th>
                <th>状态</th>
                <th>创建时间</th>
                <th>操作</th>
              </tr>
            </thead>
            <tbody>
              {blogs.map((blog) => (
                <tr key={blog.id}>
                  <td><strong>{blog.title}</strong></td>
                  <td>{blog.username}</td>
                  <td>{blog.category_name || "未分类"}</td>
                  <td>
                    <span className={`badge badge-${blog.status === "published" ? "success" : "warning"}`}>
                      {blog.status === "published" ? "已发布" : "草稿"}
                    </span>
                  </td>
                  <td>{new Date(blog.created_at).toLocaleString("zh-CN")}</td>
                  <td>
                    <div style={{ display: "flex", gap: "0.5rem" }}>
                      <button
                        onClick={() => handleEdit(blog.id)}
                        className="btn-admin btn-admin-primary"
                        style={{ padding: "0.375rem 0.75rem", fontSize: "0.8125rem" }}
                      >
                        编辑
                      </button>
                      {blog.status === "draft" && (
                        <button
                          onClick={() => handleStatusChange(blog.id, "published")}
                          className="btn-admin btn-admin-secondary"
                          style={{ padding: "0.375rem 0.75rem", fontSize: "0.8125rem" }}
                        >
                          发布
                        </button>
                      )}
                      {blog.status === "published" && (
                        <button
                          onClick={() => handleStatusChange(blog.id, "draft")}
                          className="btn-admin btn-admin-secondary"
                          style={{ padding: "0.375rem 0.75rem", fontSize: "0.8125rem" }}
                        >
                          撤回
                        </button>
                      )}
                      <button
                        onClick={() => handleDelete(blog.id, blog.title)}
                        className="btn-admin btn-admin-danger"
                        style={{ padding: "0.375rem 0.75rem", fontSize: "0.8125rem" }}
                      >
                        删除
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}

        {total > 20 && (
          <div style={{ marginTop: "1rem", display: "flex", gap: "0.5rem", justifyContent: "center" }}>
            <button
              onClick={() => setPage((p) => Math.max(1, p - 1))}
              disabled={page === 1}
              className="btn-admin btn-admin-secondary"
            >
              上一页
            </button>
            <span style={{ padding: "0.5rem 1rem" }}>第 {page} 页</span>
            <button
              onClick={() => setPage((p) => p + 1)}
              disabled={page * 20 >= total}
              className="btn-admin btn-admin-secondary"
            >
              下一页
            </button>
          </div>
        )}
      </div>

      {isEditModalOpen && (
        <div className="modal-overlay">
          <div className="modal-content" style={{ maxWidth: "800px" }}>
            <div className="modal-header">
              <h3>编辑文章</h3>
              <button className="close-btn" onClick={() => setIsEditModalOpen(false)}>&times;</button>
            </div>
            <div className="create-key-form">
              <div className="form-group">
                <label>标题</label>
                <input
                  type="text"
                  value={editingBlog.title || ""}
                  onChange={(e) => setEditingBlog({ ...editingBlog, title: e.target.value })}
                  className="admin-input"
                />
              </div>
              <div className="form-group">
                <label>分类</label>
                <select
                  value={editingBlog.category_id || ""}
                  onChange={(e) => setEditingBlog({ ...editingBlog, category_id: e.target.value ? Number(e.target.value) : null })}
                  className="admin-input"
                >
                  <option value="">未分类</option>
                  {categories.map((category) => (
                    <option key={category.id} value={category.id}>
                      {category.name}
                    </option>
                  ))}
                </select>
              </div>
              <div className="form-group">
                <label>标签 (逗号分隔)</label>
                <input
                  type="text"
                  value={editingBlog.tags || ""}
                  onChange={(e) => setEditingBlog({ ...editingBlog, tags: e.target.value })}
                  className="admin-input"
                  placeholder="AI, 工程, 创作"
                />
              </div>
              <div className="form-group">
                <label>内容</label>
                <textarea
                  value={editingBlog.content || ""}
                  onChange={(e) => setEditingBlog({ ...editingBlog, content: e.target.value })}
                  className="admin-input"
                  style={{ minHeight: "300px", fontFamily: "inherit" }}
                />
              </div>
              <div className="modal-actions">
                <button
                  className="btn-admin btn-admin-secondary"
                  onClick={() => setIsEditModalOpen(false)}
                  disabled={editLoading}
                >
                  取消
                </button>
                <button
                  className="btn-admin btn-admin-primary"
                  onClick={handleSaveEdit}
                  disabled={editLoading}
                >
                  {editLoading ? "保存中..." : "保存修改"}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";

interface FriendLink {
  id: number;
  name: string;
  url: string;
  description: string | null;
  avatar_url: string | null;
  sort_order: number;
  is_active: number;
}

export default function FriendLinksManagement() {
  const [links, setLinks] = useState<FriendLink[]>([]);
  const [loading, setLoading] = useState(true);
  const [editingId, setEditingId] = useState<number | null>(null);
  const [formData, setFormData] = useState({
    name: "",
    url: "",
    description: "",
    avatar_url: "",
    sort_order: 0,
    is_active: 1,
  });

  const getFallbackIcon = (siteUrl: string) => {
    try {
      return `${new URL(siteUrl).origin}/favicon.ico`;
    } catch {
      return "";
    }
  };

  const fetchLinks = async () => {
    try {
      const token = localStorage.getItem("token");
      const res = await fetch("/api/friend-links", {
        headers: token ? { Authorization: `Bearer ${token}` } : {},
      });
      const data = await res.json();
      setLinks(data.links || []);
      setLoading(false);
    } catch (error) {
      console.error("Failed to fetch links:", error);
      setLoading(false);
    }
  };

  useEffect(() => {
    const timer = setTimeout(() => {
      void fetchLinks();
    }, 0);
    return () => clearTimeout(timer);
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    try {
      const token = localStorage.getItem("token");

      if (editingId) {
        // Update existing link
        await fetch(`/api/friend-links/${editingId}`, {
          method: "PUT",
          headers: {
            "Content-Type": "application/json",
            Authorization: `Bearer ${token}`,
          },
          body: JSON.stringify(formData),
        });
      } else {
        // Create new link
        await fetch("/api/friend-links", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            Authorization: `Bearer ${token}`,
          },
          body: JSON.stringify(formData),
        });
      }

      // Reset form and refresh
      setFormData({
        name: "",
        url: "",
        description: "",
        avatar_url: "",
        sort_order: 0,
        is_active: 1,
      });
      setEditingId(null);
      fetchLinks();
    } catch (error) {
      console.error("Failed to save link:", error);
      alert("保存失败");
    }
  };

  const handleEdit = (link: FriendLink) => {
    setEditingId(link.id);
    setFormData({
      name: link.name,
      url: link.url,
      description: link.description || "",
      avatar_url: link.avatar_url || "",
      sort_order: link.sort_order,
      is_active: link.is_active,
    });
  };

  const handleDelete = async (id: number) => {
    if (!confirm("确定要删除这个友链吗?")) return;

    try {
      const token = localStorage.getItem("token");

      await fetch(`/api/friend-links/${id}`, {
        method: "DELETE",
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });
      fetchLinks();
    } catch (error) {
      console.error("Failed to delete link:", error);
      alert("删除失败");
    }
  };

  const handleCancel = () => {
    setEditingId(null);
    setFormData({
      name: "",
      url: "",
      description: "",
      avatar_url: "",
      sort_order: 0,
      is_active: 1,
    });
  };

  if (loading) {
    return <div className="text-center py-8">加载中...</div>;
  }

  return (
    <div className="space-y-6">
      <div className="card">
        <h2 className="text-xl font-bold mb-4">
          {editingId ? "编辑友链" : "添加友链"}
        </h2>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium mb-1">名称 *</label>
            <input
              type="text"
              className="input w-full"
              value={formData.name}
              onChange={(e) => setFormData({ ...formData, name: e.target.value })}
              required
            />
          </div>

          <div>
            <label className="block text-sm font-medium mb-1">链接 *</label>
            <input
              type="url"
              className="input w-full"
              value={formData.url}
              onChange={(e) => setFormData({ ...formData, url: e.target.value })}
              placeholder="https://example.com"
              required
            />
          </div>

          <div>
            <label className="block text-sm font-medium mb-1">描述</label>
            <textarea
              className="input w-full"
              rows={3}
              value={formData.description}
              onChange={(e) => setFormData({ ...formData, description: e.target.value })}
              placeholder="简短描述这个网站..."
            />
          </div>

          <div>
            <label className="block text-sm font-medium mb-1">站点图标 URL（可选）</label>
            <input
              type="url"
              className="input w-full"
              value={formData.avatar_url}
              onChange={(e) => setFormData({ ...formData, avatar_url: e.target.value })}
              placeholder="留空将自动检测网站图标"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-1">排序</label>
              <input
                type="number"
                className="input w-full"
                value={formData.sort_order}
                onChange={(e) => setFormData({ ...formData, sort_order: parseInt(e.target.value) || 0 })}
              />
            </div>

            <div>
              <label className="block text-sm font-medium mb-1">状态</label>
              <select
                className="input w-full"
                value={formData.is_active}
                onChange={(e) => setFormData({ ...formData, is_active: parseInt(e.target.value) })}
              >
                <option value={1}>启用</option>
                <option value={0}>禁用</option>
              </select>
            </div>
          </div>

          <div className="flex gap-2">
            <button type="submit" className="btn-primary">
              {editingId ? "更新" : "添加"}
            </button>
            {editingId && (
              <button type="button" className="btn-ghost" onClick={handleCancel}>
                取消
              </button>
            )}
          </div>
        </form>
      </div>

      <div className="card">
        <h2 className="text-xl font-bold mb-4">友链列表</h2>
        {links.length === 0 ? (
          <p className="text-muted text-center py-8">暂无友链</p>
        ) : (
          <div className="space-y-2">
            {links.map((link) => (
              <div
                key={link.id}
                className="flex items-center justify-between p-4 border border-subtle rounded-lg hover:border-blue-500/50 transition-colors"
              >
                <div className="flex items-center gap-4 flex-1 min-w-0">
                  {link.avatar_url || getFallbackIcon(link.url) ? (
                    <img
                      src={link.avatar_url || getFallbackIcon(link.url)}
                      alt={link.name}
                      className="w-12 h-12 rounded-full object-cover flex-shrink-0"
                      onError={(e) => {
                        const fallback = getFallbackIcon(link.url);
                        if (fallback && (e.currentTarget as HTMLImageElement).src !== fallback) {
                          (e.currentTarget as HTMLImageElement).src = fallback;
                          return;
                        }
                        (e.currentTarget as HTMLImageElement).style.display = "none";
                      }}
                    />
                  ) : (
                    <div className="w-12 h-12 rounded-full bg-gradient-to-br from-blue-500 to-purple-500 flex items-center justify-center text-white font-bold flex-shrink-0">
                      {link.name[0]?.toUpperCase()}
                    </div>
                  )}
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2">
                      <h3 className="font-semibold truncate">{link.name}</h3>
                      {link.is_active === 0 && (
                        <span className="text-xs px-2 py-0.5 bg-red-500/20 text-red-400 rounded">
                          已禁用
                        </span>
                      )}
                    </div>
                    <p className="text-sm text-muted truncate">{link.url}</p>
                    {link.description && (
                      <p className="text-xs text-muted mt-1 line-clamp-1">
                        {link.description}
                      </p>
                    )}
                  </div>
                </div>
                <div className="flex gap-2 flex-shrink-0">
                  <button
                    className="btn-ghost btn-sm"
                    onClick={() => handleEdit(link)}
                  >
                    编辑
                  </button>
                  <button
                    className="btn-ghost btn-sm text-red-400 hover:text-red-300"
                    onClick={() => handleDelete(link.id)}
                  >
                    删除
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

﻿"use client";

import { useEffect, useState } from "react";

export default function UserManagementPage() {
  const [users, setUsers] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [page, setPage] = useState(1);
  const [total, setTotal] = useState(0);
  const [search, setSearch] = useState("");

  useEffect(() => {
    loadUsers();
  }, [page, search]);

  useEffect(() => {
    if (typeof window === "undefined") return;
    const handler = () => loadUsers();
    window.addEventListener("profile-updated", handler as EventListener);
    return () => window.removeEventListener("profile-updated", handler as EventListener);
  }, [page, search]);

  const loadUsers = async () => {
    try {
      setLoading(true);
      const token = localStorage.getItem("token");
      const params = new URLSearchParams({
        page: page.toString(),
        limit: "20",
        ...(search ? { search } : {}),
      });

      const response = await fetch(`/api/admin/users?${params.toString()}`, {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });

      if (response.ok) {
        const data = await response.json();
        setUsers(data.data?.items || []);
        setTotal(data.data?.total || 0);
      }
    } catch (error) {
      console.error("Failed to load users:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (username: string) => {
    if (!confirm(`确定要删除用户 ${username} 吗？此操作不可恢复。`)) {
      return;
    }

    try {
      const token = localStorage.getItem("token");
      const response = await fetch(`/api/admin/users/${username}`, {
        method: "DELETE",
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });

      const data = await response.json().catch(() => ({}));
      if (data.success) {
        alert("用户删除成功");
        loadUsers();
      } else {
        alert(data.error?.message || "删除失败");
      }
    } catch (error: any) {
      alert(`删除失败: ${error.message}`);
    }
  };

  return (
    <div>
      <div className="page-header">
        <h1 className="page-title">用户管理</h1>
        <p className="page-subtitle">管理所有注册用户</p>
      </div>

      <div className="admin-card">
        <div className="card-header">
          <input
            type="text"
            placeholder="搜索用户..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="admin-input"
            style={{ width: "300px" }}
          />
          <div>共 {total} 个用户</div>
        </div>

        {loading ? null : (
          <table className="admin-table">
            <thead>
              <tr>
                <th>用户名</th>
                <th>注册时间</th>
                <th>状态</th>
                <th>操作</th>
              </tr>
            </thead>
            <tbody>
              {users.map((user) => (
                <tr key={user.username}>
                  <td><strong>{user.username}</strong></td>
                  <td>{new Date(user.created_at).toLocaleString("zh-CN")}</td>
                  <td>
                    <span className={`badge badge-${user.status === "active" ? "success" : "warning"}`}>
                      {user.status || "active"}
                    </span>
                  </td>
                  <td>
                    {user.username !== "witw" && (
                      <button
                        onClick={() => handleDelete(user.username)}
                        className="btn-admin btn-admin-danger"
                        style={{ padding: "0.375rem 0.75rem", fontSize: "0.8125rem" }}
                      >
                        删除
                      </button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}

        {total > 20 && (
          <div style={{ marginTop: "1rem", display: "flex", gap: "0.5rem", justifyContent: "center" }}>
            <button
              onClick={() => setPage((p) => Math.max(1, p - 1))}
              disabled={page === 1}
              className="btn-admin btn-admin-secondary"
            >
              上一页
            </button>
            <span style={{ padding: "0.5rem 1rem" }}>第 {page} 页</span>
            <button
              onClick={() => setPage((p) => p + 1)}
              disabled={page * 20 >= total}
              className="btn-admin btn-admin-secondary"
            >
              下一页
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

﻿"use client";

import { useState } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { resizeImageToDataUrl } from "@/utils/image";
import { useAuth } from "@/app/providers";

export default function RegisterPage() {
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [nickname, setNickname] = useState("");
  const [avatarUrl, setAvatarUrl] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const router = useRouter();
  const { login } = useAuth();

  async function handleAvatarChange(event: React.ChangeEvent<HTMLInputElement>) {
    const file = event.target.files?.[0];
    if (!file) {
      setAvatarUrl("");
      return;
    }
    const resized = await resizeImageToDataUrl(file, 256);
    setAvatarUrl(resized || "");
  }

  async function handleRegister(event: React.FormEvent) {
    event.preventDefault();
    setError("");

    if (!username.trim() || !password.trim()) {
      setError("请输入账号和密码");
      return;
    }

    if (password.length < 6) {
      setError("密码至少需要6位字符");
      return;
    }

    setLoading(true);
    try {
      const res = await fetch("/api/register", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          username,
          password,
          nickname,
          avatar_url: avatarUrl,
        }),
      });
      const data = await res.json().catch(() => ({}));
      if (!data.success) {
        setError(data.error?.message || "注册失败，请稍后重试");
        return;
      }
      if (data.data?.token && data.data?.profile) {
        login(data.data.token, data.data.profile);
      }
      router.push("/");
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="flex flex-col items-center justify-center min-h-screen bg-primary px-4">
      <div className="text-center mb-8">
        <h1 className="text-3xl font-bold mb-2">AI Studio</h1>
        <p className="text-secondary">注册后自动登录</p>
      </div>

      <form className="card form w-full max-w-md p-8 shadow-lg" onSubmit={handleRegister}>
        <label className="block mb-4">
          <span className="block mb-1 font-medium">账号</span>
          <input
            className="input"
            value={username}
            onChange={(event) => setUsername(event.target.value)}
            placeholder="设置账号"
          />
        </label>
        <label className="block mb-4">
          <span className="block mb-1 font-medium">昵称</span>
          <input
            className="input"
            value={nickname}
            onChange={(event) => setNickname(event.target.value)}
            placeholder="显示昵称"
          />
        </label>
        <label className="block mb-4">
          <span className="block mb-1 font-medium">头像</span>
          <div className="flex items-center gap-4">
            {avatarUrl && (
              <img
                src={avatarUrl}
                alt="Avatar preview"
                className="w-16 h-16 rounded-full object-cover border-2 border-accent"
              />
            )}
            <input
              type="file"
              accept="image/*"
              onChange={handleAvatarChange}
              className="text-sm text-muted file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-accent file:text-white hover:file:bg-opacity-90 cursor-pointer"
            />
          </div>
        </label>
        <label className="block mb-6">
          <span className="block mb-1 font-medium">密码</span>
          <input
            className="input"
            type="password"
            value={password}
            onChange={(event) => setPassword(event.target.value)}
            placeholder="设置密码"
          />
        </label>
        {error && (
          <p className="text-accent mb-4 text-sm bg-accent/10 p-3 rounded border border-accent/20">
            {error}
          </p>
        )}
        <button className="btn-primary w-full justify-center" type="submit" disabled={loading}>
          {loading ? "注册中..." : "注册并登录"}
        </button>
        <div className="mt-4 text-center">
          <Link className="btn-ghost text-sm" href="/login">
            已有账号？直接登录
          </Link>
        </div>
      </form>
    </div>
  );
}

"use client";

import { useState, useCallback } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/app/providers";
import { usePosts, usePostActions, useCategories } from "../hooks";
import { HeroSection } from "./hero/HeroSection";
import { SearchBar, CategoryFilter } from "./search";
import { PostList } from "./post-list";
import { Pagination } from "./pagination/Pagination";
import { Loading } from "@/components/ui/Loading";

const PAGE_SIZE = 10;

export default function BlogListPage() {
  const router = useRouter();
  const { user, token, isAuthenticated } = useAuth();

  // 筛选状态
  const [page, setPage] = useState(1);
  const [searchQuery, setSearchQuery] = useState("");
  const [submittedQuery, setSubmittedQuery] = useState("");
  const [category, setCategory] = useState("");

  // 数据获取
  const { posts, total, status, error, updatePost, totalPages } = usePosts({
    page,
    pageSize: PAGE_SIZE,
    query: submittedQuery,
    category,
    token,
  });

  const { categories } = useCategories();

  // 操作处理
  const handleAuthRequired = useCallback(() => {
    router.push("/login");
  }, [router]);

  const { like, dislike, favorite } = usePostActions({
    token,
    onUpdate: updatePost,
    onAuthRequired: handleAuthRequired,
  });

  const handleSearch = useCallback((value: string) => {
    setSubmittedQuery(value);
    setPage(1);
  }, []);

  const handleCategoryChange = useCallback((value: string) => {
    setCategory(value);
    setPage(1);
  }, []);

  const handleCommentClick = useCallback((slug: string) => {
    router.push(`/post/${slug}#comments`);
  }, [router]);

  const scrollToPosts = useCallback(() => {
    document.getElementById("posts-anchor")?.scrollIntoView({ behavior: "smooth" });
  }, []);

  const isLoading = status === "loading";
  const hasError = status === "error";

  return (
    <div className="blog-list-page">
      <HeroSection
        primaryAction={{ label: "开始阅读", onClick: scrollToPosts }}
        secondaryAction={{ label: "关于我", href: "/profile" }}
      />

      <div id="posts-anchor" className="scroll-mt-20" />

      <div className="container mx-auto max-w-4xl px-4 pt-16" style={{ minHeight: "calc(100vh - 60px)", paddingBottom: "64px" }}>
        {/* 筛选栏 */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-6">
          <h3 className="text-3xl font-bold text-white tracking-tight">最新文章</h3>
          
          <div className="flex-1 w-full md:w-auto flex flex-col md:flex-row gap-4">
            <SearchBar
              value={searchQuery}
              onChange={setSearchQuery}
              onSearch={handleSearch}
              posts={posts}
            />
            <div className="w-full md:w-[220px]">
              <CategoryFilter
                value={category}
                onChange={handleCategoryChange}
                categories={categories}
              />
            </div>
          </div>
        </div>

        {/* 状态展示 */}
        {isLoading && (
          <div className="py-16">
            <Loading size="lg" />
          </div>
        )}

        {hasError && (
          <div className="text-center py-16">
            <p className="text-red-400 mb-4">{error || "加载失败，请稍后再试。"}</p>
            <button className="btn-primary" onClick={() => window.location.reload()}>
              重试
            </button>
          </div>
        )}

        {/* 文章列表 */}
        {!isLoading && !hasError && (
          <>
            <PostList
              posts={posts}
              highlightQuery={submittedQuery}
              currentUser={user}
              onLike={like}
              onDislike={dislike}
              onFavorite={favorite}
              onCommentClick={handleCommentClick}
            />

            <Pagination
              currentPage={page}
              totalPages={totalPages}
              onPageChange={setPage}
            />
          </>
        )}
      </div>
    </div>
  );
}

