﻿"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import PostCard from "@/features/blog/components/PostCard";
import { clearAllCaches, getFavoritesCache, setFavoritesCache } from "@/utils/memoryStore";
import { getCachedJson, setCachedJson } from "@/utils/cache";
import * as blogService from "@/services/blogService";

export default function FavoritesPage() {
  const [items, setItems] = useState<any[]>([]);
  const [status, setStatus] = useState("loading");
  const [page, setPage] = useState(1);
  const [total, setTotal] = useState(0);
  const pageSize = 10;
  const router = useRouter();
  const profile = (() => {
    try {
      return JSON.parse(localStorage.getItem("profile") || "");
    } catch {
      return null;
    }
  })();
  const token = typeof window !== "undefined" ? localStorage.getItem("token") : null;
  const cacheUserKeys = [profile?.username, token, "anon"].filter(Boolean);
  const cacheKeySignature = cacheUserKeys.join("|");
  const localCacheKeys = cacheUserKeys.map((key) => `cache:favorites:${key}:${page}`);

  const loadFavorites = () => {
    const authToken = localStorage.getItem("token");
    if (!authToken) {
      router.push("/login");
      return;
    }
    let cached: any = null;
    for (const key of cacheUserKeys) {
      cached = getFavoritesCache(`${key}:${page}`);
      if (cached) break;
    }
    if (!cached) {
      for (const key of localCacheKeys) {
        cached = getCachedJson(key);
        if (cached) break;
      }
    }
    if (cached) {
      setItems(Array.isArray(cached.items) ? cached.items : []);
      setTotal(cached.total || 0);
      setStatus("ready");
      return;
    }
    setStatus("loading");
    blogService
      .getFavorites(page, pageSize)
      .then((data: any) => {
        const payload = {
          items: Array.isArray(data.items) ? data.items : [],
          total: data.total || 0,
        };
        setItems(payload.items);
        setTotal(payload.total);
        cacheUserKeys.forEach((key) => {
          setFavoritesCache(`${key}:${page}`, payload);
        });
        localCacheKeys.forEach((key) => {
          setCachedJson(key, payload);
        });
        setStatus("ready");
      })
      .catch(() => setStatus("error"));
  };

  useEffect(() => {
    // eslint-disable-next-line react-hooks/set-state-in-effect
    loadFavorites();
  }, [page, router, cacheKeySignature]);

  useEffect(() => {
    if (typeof window === "undefined") return;
    const handler = () => {
      clearAllCaches();
      try {
        Object.keys(localStorage).forEach((key) => {
          if (key.startsWith("cache:blog:") || key.startsWith("cache:post:") || key.startsWith("cache:comments:") || key.startsWith("cache:favorites:") || key.startsWith("cache:profile:")) {
            localStorage.removeItem(key);
          }
        });
      } catch { }
      loadFavorites();
    };
    window.addEventListener("profile-updated", handler as EventListener);
    return () => window.removeEventListener("profile-updated", handler as EventListener);
  }, [page, cacheKeySignature]);

  const totalPages = Math.max(1, Math.ceil(total / pageSize));

  return (
    <div className="container py-8">
      <div className="page-header mb-8">
        <div>
          <h1 className="text-3xl font-bold mb-2">我的收藏</h1>
          <p className="text-muted">您收藏的精彩内容</p>
        </div>
        <div className="actions">
          <Link className="btn-ghost" href="/">
            返回主页
          </Link>
        </div>
      </div>
      {status === "error" && <p>加载失败，请稍后再试。</p>}
      {status === "ready" && items.length === 0 && <p>暂无收藏。</p>}
      <div className="list grid">
        {items.map((post) => (
          <PostCard key={post.slug} post={post} />
        ))}
      </div>
      {totalPages > 1 && (
        <div className="pagination flex items-center justify-center gap-4 mt-8">
          <button
            className="btn-ghost"
            type="button"
            onClick={() => setPage((p) => Math.max(1, p - 1))}
            disabled={page === 1}
          >
            上一页
          </button>
          <span className="text-muted text-sm">
            第 {page} / {totalPages} 页
          </span>
          <button
            className="btn-ghost"
            type="button"
            onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
            disabled={page === totalPages}
          >
            下一页
          </button>
        </div>
      )}
    </div>
  );
}

﻿"use client";

import Link from "next/link";
import { getThumbnailUrl } from "@/utils/url";
import { ThumbsUpIcon, MessageCircleIcon, BookmarkIcon } from "@/components/Icons";
import UserHoverCard from "@/features/blog/components/UserHoverCard";

export default function PostCard({
  post,
  showActions = false,
  onLike,
  onDislike,
  onFavorite,
  onDelete,
  canEdit = false,
}: {
  post: any;
  showActions?: boolean;
  onLike?: (post: any) => void;
  onDislike?: (post: any) => void;
  onFavorite?: (post: any) => void;
  onDelete?: (post: any) => void;
  canEdit?: boolean;
}) {
  const tagList = (post.tags || "").split(",").filter(Boolean).map((t: string) => t.trim());
  const avatarUrl = getThumbnailUrl(post.author_avatar, 64);

  return (
    <div className="card post-card">
      <div className="card-head flex justify-between items-start mb-2">
        <UserHoverCard username={post.author} className="z-10">
          <div className="author flex items-center gap-2">
            {post.author_avatar ? (
              <img
                src={avatarUrl}
                alt={post.author_name || post.author}
                loading="lazy"
                decoding="async"
                className="w-6 h-6 rounded-full"
              />
            ) : (
              <div className="avatar-fallback w-6 h-6 flex items-center justify-center rounded-full bg-secondary text-xs">
                {(post.author_name || post.author || "U")?.[0]}
              </div>
            )}
            <span className="text-sm font-medium hover:text-blue-400 transition-colors uppercase">
              {post.author_name || post.author || "匿名"}
            </span>
          </div>
        </UserHoverCard>
        <span className="text-xs text-muted">{new Date(post.created_at).toLocaleString()}</span>
      </div>

      <Link href={`/post/${post.slug}`} className="block group">
        <h2 className="text-xl font-bold mb-2 leading-tight group-hover:text-blue-500 transition-colors">{post.title}</h2>

        <p className="excerpt text-muted text-sm mb-4 line-clamp-2 leading-relaxed">
          {(post.content || "").replace(/\s+/g, " ").trim().slice(0, 140)}
        </p>
      </Link>

      <div className="post-card-footer flex justify-between items-center mt-auto">
        <div className="tag-list">
          {tagList.slice(0, 3).map((tag: string) => (
            <span key={tag} className="tag-pill">#{tag}</span>
          ))}
        </div>

        {showActions ? (
          <div className="post-card-actions flex gap-1">
            {onLike && (
              <button
                className="btn-ghost btn-sm"
                type="button"
                onClick={(e) => {
                  e.preventDefault();
                  onLike(post);
                }}
              >
                <ThumbsUpIcon className="inline" /> {post.like_count ?? 0}
              </button>
            )}
            {onDislike && (
              <button
                className="btn-ghost btn-sm"
                type="button"
                onClick={(e) => {
                  e.preventDefault();
                  onDislike(post);
                }}
              >
                <ThumbsUpIcon className="inline" /> {post.dislike_count ?? 0}
              </button>
            )}
            {onFavorite && (
              <button
                className={`btn-ghost btn-sm ${post.favorited_by_me ? "text-accent" : ""}`}
                type="button"
                onClick={(e) => {
                  e.preventDefault();
                  onFavorite(post);
                }}
              >
                <BookmarkIcon filled={post.favorited_by_me} className="inline" /> {post.favorite_count ?? 0}
              </button>
            )}
            {canEdit && onDelete && (
              <button
                className="btn-ghost btn-sm text-accent"
                type="button"
                onClick={(e) => {
                  e.preventDefault();
                  onDelete(post);
                }}
              >
                删除
              </button>
            )}
          </div>
        ) : (
          <div className="post-card-actions flex gap-1">
            <span className="text-sm text-muted flex items-center gap-1">
              <ThumbsUpIcon className="inline" /> {post.like_count ?? 0}
            </span>
            <span className="text-sm text-muted flex items-center gap-1">
              <MessageCircleIcon className="inline" /> {post.comment_count ?? 0}
            </span>
            <span className="text-sm text-muted flex items-center gap-1">
              <BookmarkIcon className="inline" /> {post.favorite_count ?? 0}
            </span>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { ReactNode, useEffect, useState, useRef } from "react";
import Link from "next/link";
import { useAuth } from "@/app/providers";
import { getThumbnailUrl } from "@/utils/url";

interface UserHoverCardProps {
  username: string;
  children: ReactNode;
  className?: string;
  disableHover?: boolean;
}

export default function UserHoverCard({ username, children, className = "", disableHover = false }: UserHoverCardProps) {
  const [isVisible, setIsVisible] = useState(false);
  const [profile, setProfile] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const { token, user: authUser } = useAuth();
  const hoverTimer = useRef<NodeJS.Timeout | null>(null);
  const leaveTimer = useRef<NodeJS.Timeout | null>(null);
  const cardRef = useRef<HTMLDivElement>(null);

  const fetchProfile = async () => {
    if (profile || loading) return;
    setLoading(true);
    try {
      const res = await fetch(`/api/users/${encodeURIComponent(username)}/profile`, {
        headers: token ? { Authorization: `Bearer ${token}` } : {}
      });
      const data = await res.json();
      // 支持新的 API 格式 { success: true, data: {...} }
      setProfile(data.data || data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleMouseEnter = () => {
    if (disableHover) return;
    if (leaveTimer.current) clearTimeout(leaveTimer.current);

    hoverTimer.current = setTimeout(() => {
      setIsVisible(true);
      fetchProfile();
    }, 350); // Delay before showing
  };

  const handleMouseLeave = () => {
    if (hoverTimer.current) clearTimeout(hoverTimer.current);

    leaveTimer.current = setTimeout(() => {
      setIsVisible(false);
    }, 300); // Delay before hiding
  };

  const toggleFollow = async (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (!token || !profile) return;

    const isFollowing = profile.is_following;
    try {
      if (isFollowing) {
        await fetch(`/api/follow/${username}`, { method: "DELETE", headers: { Authorization: `Bearer ${token}` } });
      } else {
        await fetch(`/api/follow`, { method: "POST", headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` }, body: JSON.stringify({ username }) });
      }
      // Re-fetch profile to update status
      const res = await fetch(`/api/users/${encodeURIComponent(username)}/profile`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      const data = await res.json();
      // 支持新的 API 格式 { success: true, data: {...} }
      setProfile(data.data || data);
    } catch (err) {
      console.error(err);
    }
  };

  const isOwnProfile = authUser?.username === username;

  return (
    <div
      className={`relative inline-block ${className}`}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
    >
      <Link href={`/user/${username || ""}`} className="block h-full w-full">
        {children}
      </Link>

      {isVisible && (
        <div
          ref={cardRef}
          className="user-hover-card-popover"
          onMouseEnter={() => {
            if (leaveTimer.current) clearTimeout(leaveTimer.current);
          }}
          onMouseLeave={handleMouseLeave}
        >
          {loading && !profile ? (
            <div className="p-10 flex justify-center items-center">
              <div className="animate-spin rounded-full h-6 w-6 border-2 border-blue-500 border-t-transparent"></div>
            </div>
          ) : profile ? (
            <>
              {/* Cover */}
              <div
                className="hover-card-cover"
                style={profile.cover_url ? { backgroundImage: `url(${getThumbnailUrl(profile.cover_url, 400)})` } : {}}
              />

              <div className="hover-card-content">
                <div className="hover-card-info-row">
                  <Link href={`/user/${username || ""}`} className="hover-card-avatar">
                    {profile.avatar_url ? (
                      <img src={getThumbnailUrl(profile.avatar_url, 128)} alt="" />
                    ) : (
                      <div className="avatar-fallback-rect">{(username?.[0] || "?").toUpperCase()}</div>
                    )}
                  </Link>

                  <div className="hover-card-info-right">
                    <div className="hover-card-identity">
                      <Link href={`/user/${username || ""}`} className="hover-card-name" title={profile.nickname || username}>
                        {profile.nickname || username}
                      </Link>
                    </div>

                    <div className="hover-card-stats">
                      <Link href={`/following?username=${username || ""}`} className="hover-card-stat">
                        <span className="stat-value">{profile.following_count}</span>
                        <span className="stat-label">关注</span>
                      </Link>
                      <Link href={`/followers?username=${username || ""}`} className="hover-card-stat">
                        <span className="stat-value">{profile.follower_count}</span>
                        <span className="stat-label">粉丝</span>
                      </Link>
                      <div className="hover-card-stat">
                        <span className="stat-value">{profile.like_received_count || 0}</span>
                        <span className="stat-label">获赞</span>
                      </div>
                    </div>
                  </div>
                </div>

                <div className="hover-card-bio" title={profile.bio}>
                  {profile.bio || "这个人很懒，什么都没有写~"}
                </div>

                <div className="hover-card-actions">
                  {isOwnProfile ? (
                    <Link href="/profile" className="action-btn edit-btn">
                      编辑资料
                    </Link>
                  ) : (
                    <>
                      <button
                        onClick={toggleFollow}
                        className={`action-btn follow-btn ${profile.is_following ? "following" : ""}`}
                      >
                        {profile.is_following ? (
                          "已关注"
                        ) : (
                          <>
                            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
                              <line x1="12" y1="5" x2="12" y2="19"></line>
                              <line x1="5" y1="12" x2="19" y2="12"></line>
                            </svg>
                            关注
                          </>
                        )}
                      </button>
                      <Link href={`/messages?username=${username}`} className="action-btn message-btn">
                        发消息
                      </Link>
                    </>
                  )}
                </div>
              </div>
            </>
          ) : null}
        </div>
      )}
    </div>
  );
}

"use client";

import Link from "next/link";
import { memo } from "react";
import type { PostListItem } from "@/types/blog";
import { getThumbnailUrl } from "@/utils/url";
import UserHoverCard from "../UserHoverCard";
import { PostActions } from "./PostActions";

interface PostCardProps {
  post: PostListItem;
  highlightQuery?: string;
  currentUser?: {
    username: string;
    avatar_url?: string;
  } | null;
  onLike: (post: PostListItem) => void;
  onDislike: (post: PostListItem) => void;
  onFavorite: (post: PostListItem) => void;
  onCommentClick: (slug: string) => void;
}

export const PostCard = memo(function PostCard({
  post,
  highlightQuery = "",
  currentUser,
  onLike,
  onDislike,
  onFavorite,
  onCommentClick,
}: PostCardProps) {
  const titleText = post.title || "";
  const rawPreview = (post.content || "").replace(/\s+/g, " ").trim();
  const preview = rawPreview.length > 0 
    ? `${rawPreview.slice(0, 160)}${rawPreview.length > 160 ? "..." : ""}`
    : "暂无预览";
  
  const tagList = (post.tags || "")
    .split(/[,，]/)
    .map((tag) => tag.trim())
    .filter(Boolean);

  // 获取首图
  const firstImageMatch = (post.content || "").match(/!\[.*?\]\((.*?)\)|<img.*?src=["'](.*?)["']/);
  const firstImageUrl = firstImageMatch ? (firstImageMatch[1] || firstImageMatch[2]) : null;

  // 高亮匹配文字
  const matchIndex = highlightQuery ? titleText.toLowerCase().indexOf(highlightQuery.toLowerCase()) : -1;

  // 头像处理
  const effectiveAvatar = post.author === currentUser?.username && currentUser?.avatar_url
    ? currentUser.avatar_url
    : post.author_avatar;
  const avatarUrl = getThumbnailUrl(effectiveAvatar || "", 64);

  return (
    <div className="card block no-underline text-inherit">
      {/* 头部：作者和时间 */}
      <div className="card-head flex justify-between items-start mb-3">
        <UserHoverCard username={post.author}>
          <div className="author flex items-center gap-2">
            {post.author_avatar ? (
              <img
                src={avatarUrl}
                alt={post.author_name}
                loading="lazy"
                decoding="async"
                className="w-6 h-6 rounded-full"
              />
            ) : (
              <div className="avatar-fallback w-6 h-6 text-xs">{post.author_name?.[0] || "U"}</div>
            )}
            <span className="text-sm font-medium">{post.author_name || post.author || "匿名"}</span>
          </div>
        </UserHoverCard>
        <span className="text-xs text-muted">{new Date(post.created_at).toLocaleString()}</span>
      </div>

      {/* 内容区 */}
      <Link href={`/post/${post.slug}`} className="block no-underline text-inherit">
        <h2 className="text-xl font-bold mb-3 leading-tight">
          {matchIndex >= 0 ? (
            <>
              {titleText.slice(0, matchIndex)}
              <span className="highlight">
                {titleText.slice(matchIndex, matchIndex + highlightQuery.length)}
              </span>
              {titleText.slice(matchIndex + highlightQuery.length)}
            </>
          ) : (
            titleText
          )}
        </h2>

        <p className="excerpt text-muted text-sm mb-6 line-clamp-2 leading-relaxed">
          {preview}
        </p>
      </Link>

      {/* 底部：分类标签和操作 */}
      <div className="post-card-footer flex justify-between items-center mt-auto">
        <div className="post-meta-stack">
          {post.category_name && (
            <div className="category-row">
              <span className="category-chip">{post.category_name}</span>
            </div>
          )}
          {tagList.length > 0 && (
            <div className="tag-list">
              {tagList.map((tag) => (
                <span key={tag} className="tag-pill">#{tag}</span>
              ))}
            </div>
          )}
        </div>

        <PostActions
          post={post}
          onLike={() => onLike(post)}
          onDislike={() => onDislike(post)}
          onFavorite={() => onFavorite(post)}
          onComment={() => onCommentClick(post.slug)}
        />
      </div>
    </div>
  );
});

"use client";

import { useState, useEffect } from "react";
import { useAuth } from "@/app/providers";

type Friend = {
  id: number;
  username: string;
  avatar_url?: string;
  status: "online" | "idle" | "dnd" | "offline";
  activity?: string;
  type: "incoming" | "outgoing" | "friend" | "blocked";
  discriminator?: string;
};

export default function FriendsView() {
  const [activeTab, setActiveTab] = useState<"online" | "all" | "pending" | "blocked" | "add">("all");
  const [friends, setFriends] = useState<Friend[]>([]);
  const [loading, setLoading] = useState(true);
  const { token } = useAuth();

  useEffect(() => {
    async function fetchData() {
      if (!token) return;
      try {
        setLoading(true);
        const headers = { "Authorization": `Bearer ${token}` };
        const [followingRes, followersRes] = await Promise.all([
          fetch("/api/following?size=100", { headers }),
          fetch("/api/followers?size=100", { headers })
        ]);

        if (!followingRes.ok || !followersRes.ok) {
          throw new Error("Failed to fetch friends data");
        }

        const followingResponse = await followingRes.json();
        const followersResponse = await followersRes.json();

        const followingData = followingResponse.data || {};
        const followersData = followersResponse.data || {};

        const friendsMap = new Map<string, Friend>();

        // Process following (Friends or Outgoing)
        (followingData.items || []).forEach((u: any) => {
          const type = u.is_mutual ? 'friend' : 'outgoing';
          friendsMap.set(u.username, {
            id: Math.random(), // Temporary ID as API doesn't return ID directly mostly
            username: u.username,
            avatar_url: u.avatar_url,
            status: u.username === 'witw' ? 'online' : 'offline', // Mock status
            activity: u.bio,
            type: type,
            discriminator: "0000"
          });
        });

        // Process followers (Friends or Incoming)
        (followersData.items || []).forEach((u: any) => {
          if (friendsMap.has(u.username)) {
            // Already processed as mutual or outgoing, ensure it's marked as friend if mutual
            // (listFollowing already checks mutual, so mostly handled, but let's double check)
            const existing = friendsMap.get(u.username)!;
            if (u.is_following) { // is_following means ME following THEM
              existing.type = 'friend';
            }
          } else {
            // Not following them, so it's incoming
            friendsMap.set(u.username, {
              id: Math.random(),
              username: u.username,
              avatar_url: u.avatar_url,
              status: u.username === 'witw' ? 'online' : 'offline',
              activity: u.bio,
              type: 'incoming',
              discriminator: "0000"
            });
          }
        });

        setFriends(Array.from(friendsMap.values()));
      } catch (error) {
        console.error("Failed to fetch friends", error);
      } finally {
        setLoading(false);
      }
    }

    if (token) {
      fetchData();
    }
  }, [token]);

  const filteredFriends = friends.filter(f => {
    if (activeTab === "online") return f.status !== "offline" && f.type === "friend";
    if (activeTab === "all") return f.type === "friend";
    if (activeTab === "pending") return f.type === "incoming" || f.type === "outgoing";
    if (activeTab === "blocked") return f.type === "blocked";
    return false;
  });

  // ... render ...
  return (
    <div className="flex flex-col h-full bg-[#050505]">
      {/* Header */}
      <header className="h-14 flex items-center px-6 shadow-sm border-b border-[#333] shrink-0 bg-[#050505]">
        <div className="flex items-center gap-2 mr-6 border-r border-[#333] pr-6 py-1">
          <svg width="24" height="24" viewBox="0 0 24 24" fill="currentColor" className="text-[#a1a1a1]">
            <path fillRule="evenodd" clipRule="evenodd" d="M14 8.00598C14 10.211 12.206 12.006 10 12.006C7.795 12.006 6 10.211 6 8.00598C6 5.80098 7.795 4.00598 10 4.00598C12.206 4.00598 14 5.80098 14 8.00598ZM2 19.006C2 15.473 5.29 13.006 10 13.006C14.71 13.006 18 15.473 18 19.006V20.006H2V19.006Z" />
            <path d="M14 8.00598C14 10.211 15.794 12.006 18 12.006C20.206 12.006 22 10.211 22 8.00598C22 5.80098 20.206 4.00598 18 4.00598C15.794 4.00598 14 5.80098 14 8.00598Z" opacity="0.5" />
          </svg>
          <span className="font-bold text-[#ededed] text-lg">好友</span>
        </div>

        <div className="flex items-center gap-4">
          <TabButton label="在线" isActive={activeTab === "online"} onClick={() => setActiveTab("online")} />
          <TabButton label="全部" isActive={activeTab === "all"} onClick={() => setActiveTab("all")} />
          <TabButton label="待定" isActive={activeTab === "pending"} onClick={() => setActiveTab("pending")} count={1} />
          <TabButton label="已屏蔽" isActive={activeTab === "blocked"} onClick={() => setActiveTab("blocked")} />
          <button
            className={`px-4 py-1.5 rounded-full text-sm font-medium transition-all duration-200 ml-2 border 
                      ${activeTab === "add"
                ? "text-[#0070f3] bg-transparent border-[#0070f3]/30"
                : "bg-[#0070f3] text-white border-transparent hover:bg-[#0060df]"}`}
            onClick={() => setActiveTab("add")}
          >
            添加好友
          </button>
        </div>
      </header>

      {/* Content */}
      <div className="flex-1 overflow-y-auto p-0 flex flex-col">
        <div className="flex-1 flex flex-col">
          {activeTab === "add" ? (
            <div className="p-8"><AddFriend /></div>
          ) : (
            <>
              <div className="px-8 mt-6 mb-2">
                <div className="text-xs font-bold text-[#666] uppercase tracking-wider">
                  {activeTab === "online" && `在线 — ${filteredFriends.length}`}
                  {activeTab === "all" && `全部 — ${filteredFriends.length}`}
                  {activeTab === "pending" && `待定 — ${filteredFriends.length}`}
                  {activeTab === "blocked" && `已屏蔽 — ${filteredFriends.length}`}
                </div>
              </div>

              <div className="flex-1 overflow-y-auto px-4 pb-4">
                <div className="space-y-2">
                  {filteredFriends.map(friend => (
                    <FriendItem key={friend.id} friend={friend} />
                  ))}
                </div>


                {filteredFriends.length === 0 && (
                  <div className="flex flex-col items-center justify-center py-20 opacity-70">
                    <img src="/empty-friends.svg" alt="" className="w-40 h-40 mb-4 opacity-50 grayscale" onError={(e) => e.currentTarget.style.display = 'none'} />
                    <p className="text-[#666]">这里空空如也...</p>
                  </div>
                )}
              </div>
            </>
          )}
        </div>

        {/* Right Side */}
        <div className="w-[360px] pl-6 hidden xl:block">
          <h3 className="text-xl font-bold text-[#ededed] mb-4">当前活动</h3>
          <div className="bg-[#111] text-center p-8 rounded-lg border border-[#333]">
            <h4 className="text-[#ededed] font-bold mb-2">现在很安静......</h4>
            <p className="text-[#a1a1a1] text-sm">
              当好友开始活动时（比如玩游戏或进行语音聊天的时候），他们的状态都会显示在这里！
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

function TabButton({ label, isActive, onClick, count }: any) {
  return (
    <button
      onClick={onClick}
      className={`px-4 py-1.5 rounded-full text-sm font-medium transition-all duration-200
                ${isActive
          ? "bg-[#111] text-white shadow-[0_0_0_1px_#333]"
          : "text-[#a1a1a1] hover:bg-[#111] hover:text-[#ededed]"}`}
    >
      {label}
      {count > 0 && <span className="ml-2 px-1.5 py-0.5 rounded-full bg-[#0070f3] text-white text-[10px]">{count}</span>}
    </button>
  )
}

function FriendItem({ friend }: { friend: Friend }) {
  return (
    <div className="group flex items-center justify-between p-3 rounded-lg hover:bg-[#111] border-t border-[#333]/50 cursor-pointer transition-colors">
      <div className="flex items-center gap-4">
        <div className="relative">
          <div className={`w-10 h-10 rounded-full ${friend.avatar_url ? '' : 'bg-[#0070f3]'} flex items-center justify-center text-white font-medium`}>
            {friend.avatar_url ? <img src={friend.avatar_url} className="rounded-full" /> : friend.username[0].toUpperCase()}
          </div>
          <div className={`absolute -bottom-0.5 -right-0.5 w-3.5 h-3.5 rounded-full border-[3px] border-[#050505] 
                        ${friend.status === 'online' ? 'bg-green-500' :
              friend.status === 'idle' ? 'bg-yellow-500' :
                friend.status === 'dnd' ? 'bg-red-500' : 'bg-gray-500'}`}>
          </div>
        </div>
        <div>
          <div className="flex items-center gap-1">
            <span className="font-bold text-white">{friend.username}</span>
            <span className="hidden group-hover:inline text-[#dbdee1] text-xs opacity-60">#{friend.discriminator || "0000"}</span>
          </div>
          <div className="text-xs text-[#949ba4]">
            {friend.status === 'offline' ? '离线' : friend.activity || friend.status}
          </div>
        </div>
      </div>

      <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 bg-[#313338] p-1 rounded">
        <ActionButton icon={<MessageIcon />} tooltip="发消息" />
        <ActionButton icon={<MoreIcon />} tooltip="更多" />
      </div>
    </div>
  )
}

function AddFriend() {
  return (
    <div className="mt-2">
      <h3 className="uppercase text-white font-bold text-sm mb-2">添加好友</h3>
      <p className="text-[#949ba4] text-xs mb-4">你可以使用用户名来添加好友。</p>

      <div className="flex items-center bg-[#1e1f22] p-2 rounded border border-[#1e1f22] focus-within:border-[#5865f2] transition-colors">
        <input
          type="text"
          placeholder="你可以使用用户名来添加好友。 (示例: witw)"
          className="bg-transparent border-none text-white w-full focus:outline-none px-2"
        />
        <button className="bg-[#5865f2] text-white px-4 py-1.5 rounded text-sm font-medium opacity-50 cursor-not-allowed">
          发送好友请求
        </button>
      </div>

      <div className="mt-8 flex flex-col items-center opacity-70">
        <img src="/wumpus-friends.svg" className="w-64 h-40 opacity-50 grayscale" onError={(e) => e.currentTarget.style.display = 'none'} />
        <p className="text-[#949ba4] mt-4">Wumpus 正在等着新的朋友...</p>
      </div>
    </div>
  )
}

function ActionButton({ icon, tooltip }: any) {
  return (
    <div className="w-8 h-8 rounded-full bg-[#2b2d31] flex items-center justify-center text-[#dbdee1] hover:text-white cursor-pointer group/btn relative">
      {icon}
    </div>
  )
}

const MessageIcon = () => (
  <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor">
    <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-6h2v6zm0-8h-2V7h2v2z" />
  </svg>
)

const MoreIcon = () => (
  <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor">
    <path d="M12 8c1.1 0 2-.9 2-2s-.9-2-2-2-2 .9-2 2 .9 2 2 2zm0 2c-1.1 0-2 .9-2 2s.9 2 2 2 2-.9 2-2-.9-2-2-2zm0 6c-1.1 0-2 .9-2 2s.9 2 2 2 2-.9 2-2-.9-2-2-2z" />
  </svg>
)

"use client";

import { useEffect, useState, useRef } from "react";
import Link from "next/link";
import { useAuth } from "@/app/providers";
import { useSearchParams } from "next/navigation";
import { getThumbnailUrl } from "@/utils/url";

interface Conversation {
  id: number;
  last_message: string;
  last_time: string;
  unread_count: number;
  other_user: {
    username: string;
    nickname: string;
    avatar_url: string;
  };
}

interface PrivateMessage {
  id: number;
  sender: string;
  content: string;
  created_at: string;
}

interface Notification {
  id?: number;
  sender: string;
  sender_nickname: string;
  sender_avatar: string;
  content?: string;
  created_at: string;
  post_title: string;
  post_slug: string;
}

type TabType = "chat" | "replies" | "at" | "likes" | "system";

export default function MessagesPageContent() {
  const { token, user, loading: authLoading } = useAuth();
  const searchParams = useSearchParams();
  const targetUsername = searchParams.get("username");
  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [selectedConvId, setSelectedConvId] = useState<number | null>(null);
  const [messages, setMessages] = useState<PrivateMessage[]>([]);
  const [inputText, setInputText] = useState("");
  const [convLoading, setConvLoading] = useState(true);
  const [pendingConv, setPendingConv] = useState<Conversation | null>(null);

  const [activeSidebarTab, setActiveSidebarTab] = useState<TabType>("chat");
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [notifLoading, setNotifLoading] = useState(false);

  const chatEndRef = useRef<HTMLDivElement>(null);
  const chatHistoryRef = useRef<HTMLDivElement>(null);
  const lastSelectedConvId = useRef<number | null>(null);
  const lastMessagesCount = useRef<number>(0);

  const fetchConversations = async (autoSelectUsername?: string) => {
    if (!token) return;
    try {
      const res = await fetch("/api/messages/conversations", {
        headers: { Authorization: `Bearer ${token}` }
      });
      const data = await res.json();
      if (!Array.isArray(data)) {
        setConversations([]);
        return;
      }

      if (autoSelectUsername && !pendingConv) {
        const found = data.find((c: any) => c.other_user.username === autoSelectUsername);
        if (found) {
          setSelectedConvId(found.id);
        } else {
          try {
            const profileRes = await fetch(`/api/users/${encodeURIComponent(autoSelectUsername)}/profile`);
            const data = await profileRes.json();
            // 支持新的 API 格式 { success: true, data: {...} }
            const profile = data.data || data;
            if (profile && !profile.detail && profile.username) {
              const tempConv: Conversation = {
                id: -1,
                last_message: "点击此处开始发送第一条消息吧",
                last_time: new Date().toISOString(),
                unread_count: 0,
                other_user: {
                  username: profile.username,
                  nickname: profile.nickname || profile.username,
                  avatar_url: profile.avatar_url || ""
                }
              };
              setPendingConv(tempConv);
              setSelectedConvId(-1);
            }
          } catch (err) { }
        }
      }

      setConversations(data);
    } catch (err) { }
    setConvLoading(false);
  };

  const fetchNotifications = async (type: string) => {
    if (!token) return;
    setNotifLoading(true);
    try {
      const res = await fetch(`/api/messages/notifications?type=${type}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      const data = await res.json();
      setNotifications(Array.isArray(data) ? data : []);
    } catch (err) {
      setNotifications([]);
    } finally {
      setNotifLoading(false);
    }
  };

  const fetchMessages = async (id: number) => {
    if (!token) return;
    if (id === -1) {
      setMessages([]);
      return;
    }
    try {
      const res = await fetch(`/api/messages/${id}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      const data = await res.json();
      setMessages(Array.isArray(data) ? data : []);
    } catch (err) {
      setMessages([]);
    }
  };

  const handleSend = async () => {
    if (!token || !inputText.trim() || selectedConvId === null) return;

    const conv = displayConversations.find(c => c.id === selectedConvId);
    if (!conv) return;

    try {
      const res = await fetch("/api/messages/send", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`
        },
        body: JSON.stringify({
          receiver: conv.other_user.username,
          content: inputText
        })
      });
      const resData = await res.json();
      setInputText("");

      if (resData.conversation_id) {
        setPendingConv(null); // Becomes a real conversation now
        setSelectedConvId(resData.conversation_id);
        fetchMessages(resData.conversation_id);
      } else {
        fetchMessages(selectedConvId);
      }
      fetchConversations();
    } catch (err) { }
  };

  useEffect(() => {
    fetchConversations(targetUsername || undefined);
    const interval = setInterval(() => fetchConversations(), 10000);
    return () => clearInterval(interval);
  }, [token, targetUsername]);

  const displayConversations = [...conversations];
  if (pendingConv && !conversations.find(c => c.other_user.username === pendingConv.other_user.username)) {
    displayConversations.unshift(pendingConv);
  }

  useEffect(() => {
    if (selectedConvId) {
      fetchMessages(selectedConvId);
      const interval = setInterval(() => fetchMessages(selectedConvId), 5000);
      return () => clearInterval(interval);
    }
  }, [selectedConvId, token]);

  useEffect(() => {
    if (messages.length === lastMessagesCount.current && selectedConvId === lastSelectedConvId.current) return;

    const isFirstLoad = selectedConvId !== lastSelectedConvId.current;
    const isNewMessage = messages.length > lastMessagesCount.current;
    const lastMsgIsMine = messages.length > 0 && messages[messages.length - 1].sender === user?.username;

    const scrollEl = chatHistoryRef.current;
    const isNearBottom = scrollEl ? (scrollEl.scrollHeight - scrollEl.scrollTop - scrollEl.clientHeight < 100) : true;

    if (isFirstLoad) {
      if (scrollEl) {
        scrollEl.scrollTop = scrollEl.scrollHeight;
      }
    } else if (isNewMessage && (lastMsgIsMine || isNearBottom)) {
      if (scrollEl) {
        scrollEl.scrollTo({ top: scrollEl.scrollHeight, behavior: "smooth" });
      }
    }

    lastMessagesCount.current = messages.length;
    lastSelectedConvId.current = selectedConvId;
  }, [messages, selectedConvId, user]);

  useEffect(() => {
    if (activeSidebarTab !== "chat") {
      fetchNotifications(activeSidebarTab);
      fetch("/api/messages/read-notifications", {
        method: "POST",
        headers: { Authorization: `Bearer ${token}` }
      }).catch(() => { });
    }
  }, [activeSidebarTab, token]);

  const selectedConv = displayConversations.find(c => c.id === selectedConvId);

  return (
    <div className="messages-page-wrapper">
      <div className="messages-sidebar">
        <div className="sidebar-title">
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"></path>
          </svg>
          消息中心
        </div>
        <div className="sidebar-nav">
          <div
            className={`sidebar-item ${activeSidebarTab === "chat" ? "active" : ""}`}
            onClick={() => setActiveSidebarTab("chat")}
          >
            <span>我的消息</span>
            {conversations.reduce((acc, c) => acc + c.unread_count, 0) > 0 && (
              <span className="sidebar-badge">new</span>
            )}
          </div>
          <div
            className={`sidebar-item ${activeSidebarTab === "replies" ? "active" : ""}`}
            onClick={() => setActiveSidebarTab("replies")}
          >回复我的</div>
          <div
            className={`sidebar-item ${activeSidebarTab === "at" ? "active" : ""}`}
            onClick={() => setActiveSidebarTab("at")}
          >@ 我的</div>
          <div
            className={`sidebar-item ${activeSidebarTab === "likes" ? "active" : ""}`}
            onClick={() => setActiveSidebarTab("likes")}
          >收到的赞</div>
          <div
            className={`sidebar-item ${activeSidebarTab === "system" ? "active" : ""}`}
            onClick={() => setActiveSidebarTab("system")}
          >系统通知</div>
        </div>
      </div>

      <div className="messages-main-view">
        {activeSidebarTab === "chat" ? (
          <>
            <div className="chat-list-pane">
              <div className="chat-list-header">近期消息</div>
              <div className="chat-items-container">
                {displayConversations.length === 0 && !convLoading && (
                  <div className="p-4 text-center text-sm text-zinc-500">暂无消息</div>
                )}
                {displayConversations.map(conv => (
                  <div
                    key={conv.id}
                    className={`chat-item-card ${selectedConvId === conv.id ? "active" : ""}`}
                    onClick={() => setSelectedConvId(conv.id)}
                  >
                    <div className="chat-avatar-box">
                      {conv.other_user.avatar_url ? (
                        <img src={getThumbnailUrl(conv.other_user.avatar_url, 64)} alt="" />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center bg-zinc-800 text-zinc-400">
                          {conv.other_user.nickname[0].toUpperCase()}
                        </div>
                      )}
                    </div>
                    <div className="chat-info-box">
                      <div className="chat-top-row">
                        <span className="chat-name-text">{conv.other_user.nickname}</span>
                        <span className="chat-time-text">{new Date(conv.last_time).toLocaleDateString()}</span>
                      </div>
                      <div className="chat-msg-preview">{conv.last_message}</div>
                    </div>
                    {conv.unread_count > 0 && selectedConvId !== conv.id && (
                      <div className="sidebar-badge self-center">{conv.unread_count}</div>
                    )}
                  </div>
                ))}
              </div>
            </div>

            <div className="chat-view-pane">
              {authLoading ? (
                <div className="empty-chat-state">加载中...</div>
              ) : selectedConv ? (
                <>
                  <div className="chat-view-header">
                    {selectedConv.other_user.nickname}
                  </div>
                  <div className="chat-history-scroll" ref={chatHistoryRef}>
                    {(messages || []).map(msg => {
                      const isMine = msg.sender === user?.username;
                      return (
                        <div key={msg.id} className={`msg-row ${isMine ? "sent" : "received"}`}>
                          <div className="chat-avatar-box">
                            {isMine ? (
                              user?.avatar_url ? <img src={getThumbnailUrl(user.avatar_url, 64)} alt="" /> :
                                <div className="w-full h-full flex items-center justify-center bg-zinc-800 text-zinc-400 font-bold">{user?.username?.[0]?.toUpperCase()}</div>
                            ) : (
                              selectedConv.other_user.avatar_url ? <img src={getThumbnailUrl(selectedConv.other_user.avatar_url, 64)} alt="" /> :
                                <div className="w-full h-full flex items-center justify-center bg-zinc-800 text-zinc-400 font-bold">{selectedConv.other_user.username[0].toUpperCase()}</div>
                            )}
                          </div>
                          <div className="msg-content-wrapper">
                            <div className="msg-header-row">
                              {!isMine && <span className="msg-sender-name">{selectedConv.other_user.nickname}</span>}
                              <span className="msg-time-text">{new Date(msg.created_at).toLocaleString('zh-CN', { year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit' })}</span>
                            </div>
                            <div className="msg-content-bubble">
                              {msg.content}
                            </div>
                          </div>
                        </div>
                      );
                    })}
                    <div ref={chatEndRef} />
                  </div>
                  <div className="chat-input-placeholder">
                    <textarea
                      className="chat-input-textarea"
                      placeholder="发个消息聊聊吧~ (Enter 发送)"
                      value={inputText}
                      onChange={e => setInputText(e.target.value)}
                      onKeyDown={e => {
                        if (e.key === "Enter" && !e.shiftKey) {
                          e.preventDefault();
                          handleSend();
                        }
                      }}
                    />
                    <div className="chat-footer-actions">
                      <button
                        className="chat-send-action"
                        onClick={handleSend}
                        disabled={!inputText.trim()}
                      >
                        发送
                      </button>
                    </div>
                  </div>
                </>
              ) : (
                <div className="empty-chat-state">
                  选择一个联系人开始聊天
                </div>
              )}
            </div>
          </>
        ) : (
          <div className="notifications-view-pane">
            <div className="notif-header">
              {activeSidebarTab === "replies" && "回复我的"}
              {activeSidebarTab === "likes" && "收到的赞"}
              {activeSidebarTab === "at" && "@ 我的"}
              {activeSidebarTab === "system" && "系统通知"}
            </div>
            <div className="notif-list">
              {notifLoading ? (
                <div className="p-10 text-center text-zinc-500">加载中...</div>
              ) : notifications.length === 0 ? (
                <div className="p-10 text-center text-zinc-500">暂无内容</div>
              ) : (
                notifications.map((notif, idx) => (
                  <div key={idx} className="notif-item">
                    <div className="notif-avatar">
                      {notif.sender_avatar ? (
                        <img src={getThumbnailUrl(notif.sender_avatar, 64)} alt="" />
                      ) : (
                        <div className="avatar-fallback">{notif.sender_nickname[0].toUpperCase()}</div>
                      )}
                    </div>
                    <div className="notif-content">
                      <div className="notif-title">
                        <span className="sender-name">{notif.sender_nickname}</span>
                        {activeSidebarTab === "likes" && " 点赞了您的文章 "}
                        {activeSidebarTab === "replies" && " 在文章 "}
                        {activeSidebarTab === "at" && " 在文章 "}
                        {activeSidebarTab === "system" && " 向您发送了 "}

                        {activeSidebarTab !== "system" ? (
                          <Link href={`/p/${notif.post_slug}`} className="post-link">《{notif.post_title}》</Link>
                        ) : (
                          <span className="post-link">{notif.post_title}</span>
                        )}

                        {activeSidebarTab === "replies" && " 中回复了您"}
                        {activeSidebarTab === "at" && " 中提及了您"}
                      </div>
                      {notif.content && <div className="notif-text">{notif.content}</div>}
                      <div className="notif-time">{new Date(notif.created_at).toLocaleString()}</div>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useAuth } from "@/app/providers";
import Link from "next/link";
import { useSearchParams } from "next/navigation";

export default function FollowersPageContent() {
  const { token } = useAuth();
  const searchParams = useSearchParams();
  const username = searchParams.get("username");

  const [items, setItems] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  const loadItems = async () => {
    setLoading(true);
    try {
      const url = username
        ? `/api/followers?username=${encodeURIComponent(username)}&page=1&size=50`
        : `/api/followers?page=1&size=50`;
      const res = await fetch(url, {
        headers: token ? { Authorization: `Bearer ${token}` } : {},
      });
