 * 用于升级现有数据
 */
export function migratePlaintextConfig(key: SensitiveConfigKey, plaintextValue: string): boolean {
  try {
    setSecureConfig(key, plaintextValue);
    console.log(`[SecureConfig] Migrated ${key} to encrypted storage`);
    return true;
  } catch (error) {
    console.error(`[SecureConfig] Failed to migrate ${key}:`, error);
    return false;
  }
}

/**
 * 批量迁移配置
 * @param configs 配置对象
 */
export function batchMigrateConfigs(configs: Partial<Record<SensitiveConfigKey, string>>): {
  success: string[];
  failed: string[];
} {
  const success: string[] = [];
  const failed: string[] = [];
  
  for (const [key, value] of Object.entries(configs)) {
    if (value && migratePlaintextConfig(key as SensitiveConfigKey, value)) {
      success.push(key);
    } else {
      failed.push(key);
    }
  }
  
  return { success, failed };
}

/**
 * 安全中间件
 * 提供 API 路由的安全增强功能
 */

import { NextRequest } from "next/server";
import { 
  getSecurityHeaders, 
  checkRateLimit, 
  validateRequest,
  ValidationError 
} from "./security";
import { securityConfig } from "./config";
import { getAuthUser } from "./http";

export interface SecurityContext {
  ip: string;
  userAgent?: string;
  user?: string;
  isAuthenticated: boolean;
}

/**
 * 获取客户端 IP 地址
 */
function getClientIp(req: NextRequest): string {
  // 优先从 X-Forwarded-For 获取（当使用代理时）
  const forwarded = req.headers.get("x-forwarded-for");
  if (forwarded) {
    return forwarded.split(",")[0].trim();
  }
  
  // 从 X-Real-IP 获取
  const realIp = req.headers.get("x-real-ip");
  if (realIp) {
    return realIp;
  }
  
  // 回退（NextRequest 的 ip 属性可能在某些版本中不可用）
  return (req as any).ip || "unknown";
}

/**
 * 创建带安全响应头的 Response
 */
export function createSecureResponse(
  body: BodyInit | null,
  init?: ResponseInit
): Response {
  const headers = new Headers(init?.headers);
  
  // 添加安全响应头
  const securityHeaders = getSecurityHeaders();
  Object.entries(securityHeaders).forEach(([key, value]) => {
    headers.set(key, value);
  });
  
  return new Response(body, {
    ...init,
    headers,
  });
}

/**
 * 创建 JSON 响应（带安全头）
 */
export function createJsonResponse(
  data: unknown,
  status: number = 200,
  additionalHeaders?: Record<string, string>
): Response {
  const headers = new Headers({
    "Content-Type": "application/json",
    ...additionalHeaders,
  });
  
  // 添加安全响应头
  const securityHeaders = getSecurityHeaders();
  Object.entries(securityHeaders).forEach(([key, value]) => {
    headers.set(key, value);
  });
  
  return Response.json(data, { status, headers });
}

/**
 * 速率限制中间件
 * @param req NextRequest 对象
 * @param maxRequests 最大请求数
 * @param windowMs 时间窗口
 * @returns null 表示通过，Response 表示被限制
 */
export function rateLimitMiddleware(
  req: NextRequest,
  maxRequests?: number,
  windowMs?: number
): Response | null {
  const ip = getClientIp(req);
  const max = maxRequests ?? securityConfig.rateLimitMax;
  const window = windowMs ?? securityConfig.rateLimitWindow;
  
  const result = checkRateLimit(`rate_limit:${ip}`, max, window);
  
  if (!result.allowed) {
    const headers = new Headers(getSecurityHeaders());
    headers.set("Retry-After", String(Math.ceil((result.resetTime - Date.now()) / 1000)));
    headers.set("X-RateLimit-Limit", String(max));
    headers.set("X-RateLimit-Remaining", "0");
    headers.set("X-RateLimit-Reset", String(Math.ceil(result.resetTime / 1000)));
    
    return new Response(
      JSON.stringify({
        error: "Rate limit exceeded",
        message: "Too many requests, please try again later",
        retryAfter: Math.ceil((result.resetTime - Date.now()) / 1000),
      }),
      {
        status: 429,
        headers,
      }
    );
  }
  
  // 添加速率限制信息到请求头（供后续使用）
  req.headers.set("X-RateLimit-Limit", String(max));
  req.headers.set("X-RateLimit-Remaining", String(result.remaining));
  req.headers.set("X-RateLimit-Reset", String(Math.ceil(result.resetTime / 1000)));
  
  return null;
}

/**
 * API 路由的严格速率限制（更严格的限制）
 */
export function apiRateLimit(req: NextRequest): Response | null {
  return rateLimitMiddleware(
    req,
    securityConfig.apiRateLimitMax,
    securityConfig.rateLimitWindow
  );
}

/**
 * 登录路由的严格速率限制（防暴力破解）
 */
export function loginRateLimit(req: NextRequest): Response | null {
  const ip = getClientIp(req);
  const result = checkRateLimit(
    `login_limit:${ip}`,
    securityConfig.loginRateLimitMax,
    securityConfig.loginRateLimitWindow
  );
  
  if (!result.allowed) {
    const headers = new Headers(getSecurityHeaders());
    headers.set("Retry-After", String(Math.ceil((result.resetTime - Date.now()) / 1000)));
    
    return new Response(
      JSON.stringify({
        error: "Too many login attempts",
        message: "Please try again later",
        retryAfter: Math.ceil((result.resetTime - Date.now()) / 1000),
      }),
      {
        status: 429,
        headers,
      }
    );
  }
  
  return null;
}

/**
 * 验证请求体中间件
 * @param body 请求体
 * @param rules 验证规则
 * @returns 验证结果或错误响应
 */
export function validateRequestMiddleware<T extends Record<string, any>>(
  body: unknown,
  rules: Parameters<typeof validateRequest<T>>[1]
): 
  | { valid: true; data: T; errors?: undefined }
  | { valid: false; data?: undefined; errors: ValidationError[]; response: Response } {
  const result = validateRequest<T>(body, rules);
  
  if (!result.valid) {
    return {
      valid: false,
      errors: result.errors!,
      response: createJsonResponse(
        {
          error: "Validation failed",
          details: result.errors,
        },
        400
      ),
    };
  }
  
  return { valid: true, data: result.data! };
}

/**
 * 认证中间件
 * @param req NextRequest 对象
 * @returns 用户ID或错误响应
 */
export async function authMiddleware(req: NextRequest): Promise<string | Response> {
  const user = await getAuthUser();
  
  if (!user) {
    return createJsonResponse(
      {
        error: "Unauthorized",
        message: "Authentication required",
      },
      401
    );
  }
  
  return user;
}

/**
 * 管理员认证中间件
 * @param req NextRequest 对象
 * @returns 用户ID或错误响应
 */
export async function adminAuthMiddleware(req: NextRequest): Promise<string | Response> {
  const user = await getAuthUser();
  
  if (!user) {
    return createJsonResponse(
      {
        error: "Unauthorized",
        message: "Authentication required",
      },
      401
    );
  }
  
  const { isAdminUser } = await import("./http");
  if (!isAdminUser(user)) {
    return createJsonResponse(
      {
        error: "Forbidden",
        message: "Admin access required",
      },
      403
    );
  }
  
  return user;
}

/**
 * 创建安全上下文
 * @param req NextRequest 对象
 * @returns 安全上下文
 */
export async function createSecurityContext(req: NextRequest): Promise<SecurityContext> {
  const user = await getAuthUser();
  
  return {
    ip: getClientIp(req),
    userAgent: req.headers.get("user-agent") || undefined,
    user: user || undefined,
    isAuthenticated: !!user,
  };
}

/**
 * 安全日志记录
 * 记录安全相关事件
 */
export function securityLog(
  event: string,
  context: SecurityContext,
  details?: Record<string, any>
): void {
  const timestamp = new Date().toISOString();
  const logEntry = {
    timestamp,
    event,
    ip: context.ip,
    user: context.user,
    userAgent: context.userAgent,
    ...details,
  };
  
  // 在生产环境可以发送到日志服务
  if (process.env.NODE_ENV === "production") {
    console.log("[SECURITY]", JSON.stringify(logEntry));
  } else {
    console.log("[SECURITY]", event, { ip: context.ip, user: context.user, ...details });
  }
}

/**
 * 组合中间件执行器
 * 按顺序执行多个中间件，如果有返回 Response 则停止
 */
export async function executeMiddlewares(
  req: NextRequest,
  middlewares: Array<(req: NextRequest) => Response | null | Promise<Response | null>>
): Promise<Response | null> {
  for (const middleware of middlewares) {
    const result = await middleware(req);
    if (result) {
      return result;
    }
  }
  return null;
}

/**
 * 安全工具函数模块
 * 提供加密/解密、SQL注入防护、输入清理等安全功能
 */

import crypto from "crypto";
import { NextRequest } from "next/server";

// ============================================================================
// 加密/解密配置
// ============================================================================

const ENCRYPTION_ALGORITHM = "aes-256-gcm";
const KEY_LENGTH = 32;
const IV_LENGTH = 16;
const AUTH_TAG_LENGTH = 16;
const SALT_LENGTH = 64;

/**
 * 从环境变量获取加密密钥，如果没有则生成一个（仅用于开发环境）
 */
function getEncryptionKey(): Buffer {
  const envKey = process.env.ENCRYPTION_KEY;
  if (envKey && envKey.length >= 32) {
    return Buffer.from(envKey.slice(0, 32));
  }
  // 开发环境回退（生产环境应该总是设置 ENCRYPTION_KEY）
  console.warn("[SECURITY WARNING] ENCRYPTION_KEY not set, using fallback key");
  return crypto.scryptSync("fallback-dev-key-do-not-use-in-production", "salt", KEY_LENGTH);
}

/**
 * 生成随机密钥（用于初始化时生成环境变量值）
 */
export function generateEncryptionKey(): string {
  return crypto.randomBytes(KEY_LENGTH).toString("hex");
}

// ============================================================================
// 加密/解密函数
// ============================================================================

export interface EncryptedData {
  encrypted: string;      // base64 编码的加密数据
  iv: string;             // base64 编码的初始化向量
  authTag: string;        // base64 编码的认证标签
  salt: string;           // base64 编码的盐值
}

/**
 * 加密敏感数据
 * @param text 要加密的明文
 * @returns 加密后的数据对象
 */
export function encrypt(text: string): EncryptedData {
  const salt = crypto.randomBytes(SALT_LENGTH);
  const iv = crypto.randomBytes(IV_LENGTH);
  
  // 使用 HKDF 派生密钥
  const key = crypto.scryptSync(getEncryptionKey(), salt, KEY_LENGTH);
  
  const cipher = crypto.createCipheriv(ENCRYPTION_ALGORITHM, key, iv);
  
  let encrypted = cipher.update(text, "utf8", "base64");
  encrypted += cipher.final("base64");
  
  const authTag = cipher.getAuthTag();
  
  return {
    encrypted,
    iv: iv.toString("base64"),
    authTag: authTag.toString("base64"),
    salt: salt.toString("base64"),
  };
}

/**
 * 解密敏感数据
 * @param data 加密数据对象
 * @returns 解密后的明文
 */
export function decrypt(data: EncryptedData): string {
  try {
    const salt = Buffer.from(data.salt, "base64");
    const iv = Buffer.from(data.iv, "base64");
    const authTag = Buffer.from(data.authTag, "base64");
    
    const key = crypto.scryptSync(getEncryptionKey(), salt, KEY_LENGTH);
    
    const decipher = crypto.createDecipheriv(ENCRYPTION_ALGORITHM, key, iv);
    decipher.setAuthTag(authTag);
    
    let decrypted = decipher.update(data.encrypted, "base64", "utf8");
    decrypted += decipher.final("utf8");
    
    return decrypted;
  } catch (error) {
    throw new Error("Decryption failed: invalid data or key");
  }
}

/**
 * 加密字符串并返回 JSON 字符串（便于存储）
 */
export function encryptToString(text: string): string {
  return JSON.stringify(encrypt(text));
}

/**
 * 从 JSON 字符串解密
 */
export function decryptFromString(encryptedString: string): string {
  const data = JSON.parse(encryptedString) as EncryptedData;
  return decrypt(data);
}

// ============================================================================
// SQL 注入防护
// ============================================================================

// SQL 关键字和危险字符
const SQL_KEYWORDS = [
  "SELECT", "INSERT", "UPDATE", "DELETE", "DROP", "CREATE", "ALTER",
  "EXEC", "EXECUTE", "UNION", "NULL", "CAST", "DECLARE", "TRUNCATE",
  "--", "/*", "*/", ";", "'", "\"", "`", "xp_", "sp_", "sysobjects",
  "syscolumns", "WAITFOR", "DELAY", "SHUTDOWN", "CHAR(", "NCHAR(",
];

const SQL_PATTERN = new RegExp(
  SQL_KEYWORDS.map(k => k.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")).join("|"),
  "i"
);

/**
 * 检测潜在的 SQL 注入攻击
 * @param input 要检查的输入
 * @returns 是否包含潜在的 SQL 注入
 */
export function detectSqlInjection(input: string): boolean {
  if (!input || typeof input !== "string") return false;
  
  // 检查常见的 SQL 注入模式
  const dangerousPatterns = [
    /(\%27)|(\')|(\-\-)|(\%23)|(#)/i,  // 单引号、注释
    /((\%3D)|(=))[^\n]*((\%27)|(\')|(\-\-)|(\%3B)|(;))/i,  // = 后面跟引号
    /\w*((\%27)|(\'))((\%6F)|o|(\%4F))((\%72)|r|(\%52))/i,  // 'or'
    /((\%27)|(\'))union/i,  // 'union
    /exec(\s|\+)+(s|x)p\w+/i,  // exec xp_
    /UNION\s+SELECT/i,  // UNION SELECT
    /INSERT\s+INTO/i,  // INSERT INTO
    /DELETE\s+FROM/i,  // DELETE FROM
    /DROP\s+TABLE/i,  // DROP TABLE
  ];
  
  return dangerousPatterns.some(pattern => pattern.test(input));
}

/**
 * 清理 SQL 通配符，用于 LIKE 查询
 * @param input 原始输入
 * @returns 清理后的输入（保留 % 和 _ 作为通配符，但转义特殊字符）
 */
export function sanitizeLikePattern(input: string): string {
  if (!input || typeof input !== "string") return "";
  
  // 转义 LIKE 特殊字符：\ % _
  return input
    .replace(/\\/g, "\\\\")  // 先转义反斜杠
    .replace(/%/g, "\\%")     // 转义 %
    .replace(/_/g, "\\_");    // 转义 _
}

/**
 * 验证表名/列名（只允许字母、数字、下划线）
 * @param identifier 标识符
 * @returns 是否有效
 */
export function isValidSqlIdentifier(identifier: string): boolean {
  if (!identifier || typeof identifier !== "string") return false;
  // 只允许字母、数字、下划线，且不能以数字开头
  return /^[a-zA-Z_][a-zA-Z0-9_]*$/.test(identifier);
}

/**
 * 安全的 SQL 排序字段验证
 * @param sortField 排序字段
 * @param allowedFields 允许的字段列表
 * @returns 验证后的字段（如果无效则返回默认字段）
 */
export function validateSortField(
  sortField: string,
  allowedFields: string[],
  defaultField: string = "id"
): string {
  if (!sortField || typeof sortField !== "string") return defaultField;
  
  // 提取字段名（去除可能的 ASC/DESC）
  const field = sortField.replace(/\s+(ASC|DESC)$/i, "").trim();
  
  // 检查是否在允许列表中
  if (allowedFields.includes(field) && isValidSqlIdentifier(field)) {
    // 重新组装带排序方向的字段
    const direction = /\s+DESC$/i.test(sortField) ? "DESC" : "ASC";
    return `${field} ${direction}`;
  }
  
  return defaultField;
}

// ============================================================================
// 输入验证和清理
// ============================================================================

/**
 * 清理 HTML 特殊字符，防止 XSS
 * @param input 原始输入
 * @returns 清理后的输入
 */
export function escapeHtml(input: string): string {
  if (!input || typeof input !== "string") return "";
  
  const htmlEscapes: Record<string, string> = {
    "&": "&amp;",
    "<": "&lt;",
    ">": "&gt;",
    '"': "&quot;",
    "'": "&#x27;",
    "/": "&#x2F;",
  };
  
  return input.replace(/[&<>"'/]/g, char => htmlEscapes[char] || char);
}

/**
 * 验证用户名格式
 * @param username 用户名
 * @returns 是否有效
 */
export function isValidUsername(username: string): boolean {
  if (!username || typeof username !== "string") return false;
  // 只允许字母、数字、下划线、连字符，长度 3-30
  return /^[a-zA-Z0-9_-]{3,30}$/.test(username);
}

/**
 * 验证邮箱格式
 * @param email 邮箱
 * @returns 是否有效
 */
export function isValidEmail(email: string): boolean {
  if (!email || typeof email !== "string") return false;
  // 基本的邮箱格式验证
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

/**
 * 验证密码强度
 * @param password 密码
 * @returns 验证结果
 */
export function validatePassword(password: string): {
  valid: boolean;
  errors: string[];
} {
  const errors: string[] = [];
  
  if (!password || typeof password !== "string") {
    return { valid: false, errors: ["Password is required"] };
  }
  
  if (password.length < 8) {
    errors.push("Password must be at least 8 characters long");
  }
  
  if (password.length > 128) {
    errors.push("Password must not exceed 128 characters");
  }
  
  if (!/[a-z]/.test(password)) {
    errors.push("Password must contain at least one lowercase letter");
  }
  
  if (!/[A-Z]/.test(password)) {
    errors.push("Password must contain at least one uppercase letter");
  }
  
  if (!/[0-9]/.test(password)) {
    errors.push("Password must contain at least one number");
  }
  
  return {
    valid: errors.length === 0,
    errors,
  };
}

/**
 * 验证分页参数
 * @param page 页码
 * @param limit 每页数量
 * @param maxLimit 最大每页数量
 * @returns 验证后的分页参数
 */
export function validatePagination(
  page: number | string,
  limit: number | string,
  maxLimit: number = 100
): { page: number; limit: number } {
  let parsedPage = typeof page === "string" ? parseInt(page, 10) : page;
  let parsedLimit = typeof limit === "string" ? parseInt(limit, 10) : limit;
  
  if (isNaN(parsedPage) || parsedPage < 1) parsedPage = 1;
  if (isNaN(parsedLimit) || parsedLimit < 1) parsedLimit = 20;
  if (parsedLimit > maxLimit) parsedLimit = maxLimit;
  
  return { page: parsedPage, limit: parsedLimit };
}

/**
 * 清理用户输入（去除首尾空格、控制字符）
 * @param input 原始输入
 * @returns 清理后的输入
 */
export function sanitizeInput(input: string): string {
  if (!input || typeof input !== "string") return "";
  
  return input
    .trim()
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, "");  // 移除控制字符
}

// ============================================================================
// 请求验证中间件
// ============================================================================

export interface ValidationError {
  field: string;
  message: string;
}

/**
 * 验证请求体
 * @param body 请求体
 * @param rules 验证规则
 * @returns 验证结果
 */
export function validateRequest<T extends Record<string, any>>(
  body: unknown,
  rules: {
    [K in keyof T]: {
      required?: boolean;
      type?: "string" | "number" | "boolean" | "array" | "object";
      minLength?: number;
      maxLength?: number;
      pattern?: RegExp;
      validator?: (value: any) => boolean | string;
    };
  }
): { valid: boolean; data?: T; errors?: ValidationError[] } {
  if (!body || typeof body !== "object") {
    return { valid: false, errors: [{ field: "body", message: "Invalid request body" }] };
  }
  
  const errors: ValidationError[] = [];
  const data = {} as T;
  
  for (const [field, rule] of Object.entries(rules)) {
    const value = (body as Record<string, any>)[field];
    
    // 检查必填
    if (rule.required && (value === undefined || value === null || value === "")) {
      errors.push({ field, message: `${String(field)} is required` });
      continue;
    }
    
    // 如果未提供且非必填，跳过
    if (value === undefined || value === null) {
      continue;
    }
    
    // 类型检查
    if (rule.type) {
      const actualType = Array.isArray(value) ? "array" : typeof value;
      if (actualType !== rule.type) {
        errors.push({ field, message: `${String(field)} must be of type ${rule.type}` });
        continue;
      }
    }
    
    // 字符串长度检查
    if (typeof value === "string") {
      if (rule.minLength !== undefined && value.length < rule.minLength) {
        errors.push({ field, message: `${String(field)} must be at least ${rule.minLength} characters` });
        continue;
      }
      if (rule.maxLength !== undefined && value.length > rule.maxLength) {
        errors.push({ field, message: `${String(field)} must not exceed ${rule.maxLength} characters` });
        continue;
      }
      if (rule.pattern && !rule.pattern.test(value)) {
        errors.push({ field, message: `${String(field)} format is invalid` });
        continue;
      }
    }
    
    // 自定义验证器
    if (rule.validator) {
      const result = rule.validator(value);
      if (result !== true) {
        errors.push({ field, message: typeof result === "string" ? result : `${String(field)} is invalid` });
        continue;
      }
    }
    
    (data as any)[field] = value;
  }
  
  if (errors.length > 0) {
    return { valid: false, errors };
  }
  
  return { valid: true, data };
}

