/**
 * 掩码敏感字符串（如 API 密钥）
 * @param value 原始值
 * @param visibleStart 开头保留的字符数
 * @param visibleEnd 结尾保留的字符数
 * @returns 掩码后的字符串
 */
export function maskSensitiveValue(
  value: string,
  visibleStart: number = 4,
  visibleEnd: number = 4
): string {
  if (!value || typeof value !== "string") return "";
  if (value.length <= visibleStart + visibleEnd) return "*".repeat(value.length);
  
  const start = value.slice(0, visibleStart);
  const end = value.slice(-visibleEnd);
  const middleLength = value.length - visibleStart - visibleEnd;
  
  return `${start}${"*".repeat(middleLength)}${end}`;
}

/**
 * 从对象中移除敏感字段（用于日志输出）
 * @param obj 原始对象
 * @param sensitiveFields 敏感字段名列表
 * @returns 处理后的对象
 */
export function sanitizeForLogging<T extends Record<string, any>>(
  obj: T,
  sensitiveFields: string[] = ["password", "token", "api_key", "secret", "authorization"]
): Partial<T> {
  const result = { ...obj };
  
  for (const field of sensitiveFields) {
    if (field in result) {
      (result as any)[field] = "[REDACTED]";
    }
  }
  
  return result;
}

/**
 * 请求校验工具
 * 使用 Zod 进行请求体验证
 */

import { z, ZodError, type ZodType } from "zod";
import { ApiError, ErrorCode } from "./api-error";

// ============== 类型定义 ==============

// 验证结果
export interface ValidationResult<T> {
  success: true;
  data: T;
}

export interface ValidationError {
  success: false;
  errors: ValidationFieldError[];
}

export interface ValidationFieldError {
  field: string;
  message: string;
  value?: unknown;
}

// ============== Zod 错误格式化 ==============

/**
 * 将 ZodError 格式化为字段错误数组
 */
export function formatZodErrors(error: ZodError): ValidationFieldError[] {
  return error.issues.map((issue) => ({
    field: issue.path.join("."),
    message: issue.message,
    value: undefined, // Zod 不直接暴露原始值，出于安全考虑
  }));
}

/**
 * 将 ZodError 格式化为对象（字段 -> 错误消息）
 */
export function formatZodErrorsAsObject(
  error: ZodError
): Record<string, string> {
  const result: Record<string, string> = {};
  error.issues.forEach((issue) => {
    const field = issue.path.join(".") || "root";
    if (!result[field]) {
      result[field] = issue.message;
    }
  });
  return result;
}

// ============== 同步验证 ==============

/**
 * 同步验证数据
 * @param schema - Zod Schema
 * @param data - 待验证的数据
 * @returns 验证结果
 */
export function validate<T>(schema: ZodType<T>, data: unknown): ValidationResult<T> | ValidationError {
  const result = schema.safeParse(data);
  
  if (result.success) {
    return { success: true, data: result.data };
  }
  
  return {
    success: false,
    errors: formatZodErrors(result.error),
  };
}

/**
 * 同步验证，失败时抛出 ApiError
 * @param schema - Zod Schema
 * @param data - 待验证的数据
 * @param errorMessage - 自定义错误消息
 * @returns 验证后的数据
 * @throws ApiError
 */
export function validateOrThrow<T>(
  schema: ZodType<T>,
  data: unknown,
  errorMessage?: string
): T {
  const result = schema.safeParse(data);
  
  if (result.success) {
    return result.data;
  }
  
  throw ApiError.validation(
    errorMessage || "请求数据验证失败",
    formatZodErrorsAsObject(result.error)
  );
}

// ============== 异步验证（请求体验证） ==============

export interface RequestValidationOptions {
  /** 自定义错误消息 */
  message?: string;
  /** 是否在验证前清理数据 */
  strip?: boolean;
}

/**
 * 验证请求体（JSON）
 * @param req - Request 对象
 * @param schema - Zod Schema
 * @param options - 验证选项
 * @returns 验证后的数据
 * @throws ApiError
 */
export async function validateBody<T>(
  req: Request,
  schema: ZodType<T>,
  options: RequestValidationOptions = {}
): Promise<T> {
  let body: unknown;
  
  try {
    body = await req.clone().json();
  } catch {
    throw ApiError.badRequest("请求体必须是有效的 JSON");
  }
  
  const result = schema.safeParse(body);
  
  if (result.success) {
    return result.data;
  }
  
  throw ApiError.validation(
    options.message || "请求体验证失败",
    formatZodErrorsAsObject(result.error)
  );
}

/**
 * 验证查询参数
 * @param req - Request 对象
 * @param schema - Zod Schema（字符串值会自动转换）
 * @param options - 验证选项
 * @returns 验证后的数据
 * @throws ApiError
 */
export async function validateQuery<T>(
  req: Request,
  schema: ZodType<T>,
  options: RequestValidationOptions = {}
): Promise<T> {
  const url = new URL(req.url);
  const params: Record<string, unknown> = {};
  
  // 将所有查询参数收集为对象
  url.searchParams.forEach((value, key) => {
    // 处理数组参数（如 ?tag=a&tag=b）
    const existing = params[key];
    if (existing !== undefined) {
      if (Array.isArray(existing)) {
        existing.push(value);
      } else {
        params[key] = [existing, value];
      }
    } else {
      params[key] = value;
    }
  });
  
  const result = schema.safeParse(params);
  
  if (result.success) {
    return result.data;
  }
  
  throw ApiError.validation(
    options.message || "查询参数验证失败",
    formatZodErrorsAsObject(result.error)
  );
}

/**
 * 验证路由参数（用于动态路由如 [id]）
 * @param params - 路由参数对象
 * @param schema - Zod Schema
 * @param options - 验证选项
 * @returns 验证后的数据
 * @throws ApiError
 */
export function validateParams<T>(
  params: Record<string, string | string[] | undefined>,
  schema: ZodType<T>,
  options: RequestValidationOptions = {}
): T {
  const result = schema.safeParse(params);
  
  if (result.success) {
    return result.data;
  }
  
  throw ApiError.validation(
    options.message || "路由参数验证失败",
    formatZodErrorsAsObject(result.error)
  );
}

// ============== 常用 Schema 辅助 ==============

/**
 * 创建分页查询参数的 Schema
 */
export function createPaginationSchema(defaultPage = 1, defaultSize = 10) {
  return z.object({
    page: z.coerce.number().int().min(1).default(defaultPage),
    size: z.coerce.number().int().min(1).max(100).default(defaultSize),
  });
}

/**
 * 创建 ID 参数的 Schema（用于路由参数）
 */
export function createIdParamSchema(fieldName = "id") {
  return z.object({
    [fieldName]: z.coerce.number().int().positive(),
  });
}

/**
 * 创建字符串 ID 参数的 Schema
 */
export function createStringIdParamSchema(fieldName = "id") {
  return z.object({
    [fieldName]: z.string().min(1),
  });
}

/**
 * 创建搜索查询参数的 Schema
 */
export function createSearchSchema() {
  return z.object({
    q: z.string().optional().default(""),
    ...createPaginationSchema().shape,
  });
}

