/**
 * 错误处理中间件
 * 
 * 注意：Next.js App Router 不支持传统的 Connect 风格中间件
 * 本文件提供错误处理的辅助函数和模式，用于在 API Routes 中统一处理错误
 */

import { NextRequest, NextResponse } from "next/server";
import {
  ApiError,
  isApiError,
  ErrorCode,
  type ErrorCodeType,
  HttpStatus,
  errorResponse,
  apiErrorResponse,
  handleError,
} from "@/lib/api-response";

// ============== API Route 错误处理包装器 ==============

/**
 * API Route 处理函数类型
 * 支持返回成功响应或错误响应的联合类型
 */
export type ApiHandler<T = unknown> = (
  req: NextRequest,
  context?: { params: Promise<Record<string, string | string[]>> }
) => Promise<NextResponse<T>> | NextResponse<T>;

/**
 * 扩展的 API Handler 类型，支持返回联合类型
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export type FlexibleApiHandler<TParams = any> = (
  req: NextRequest,
  context: { params: Promise<TParams> }
) => Promise<NextResponse<any>> | NextResponse<any>;

/**
 * 包装 API Route 处理函数，自动捕获和处理错误
 * 
 * 使用示例：
 * ```typescript
 * // app/api/example/route.ts
 * import { withErrorHandler } from "@/middleware/error-handler";
 * import { successResponse } from "@/lib/api-response";
 * 
 * export const GET = withErrorHandler(async (req) => {
 *   const data = await fetchData();
 *   return successResponse(data);
 * });
 * 
 * export const POST = withErrorHandler(async (req) => {
 *   const body = await req.json();
 *   const result = await createData(body);
 *   return successResponse(result, 201);
 * });
 * ```
 */
export function withErrorHandler(handler: FlexibleApiHandler): FlexibleApiHandler {
  return async (req, context) => {
    try {
      return await handler(req, context);
    } catch (error) {
      return handleError(error);
    }
  };
}

/**
 * 创建一个完整的 CRUD API Route 处理器
 * 
 * 使用示例：
 * ```typescript
 * // app/api/items/route.ts
 * import { createApiRoute } from "@/middleware/error-handler";
 * 
 * export const { GET, POST } = createApiRoute({
 *   GET: async (req) => {
 *     const items = await getItems();
 *     return successResponse(items);
 *   },
 *   POST: async (req) => {
 *     const body = await validateBody(req, createItemSchema);
 *     const item = await createItem(body);
 *     return successResponse(item, 201);
 *   },
 * });
 * ```
 */
export function createApiRoute(handlers: {
  GET?: FlexibleApiHandler;
  POST?: FlexibleApiHandler;
  PUT?: FlexibleApiHandler;
  PATCH?: FlexibleApiHandler;
  DELETE?: FlexibleApiHandler;
}) {
  const wrappedHandlers: Record<string, FlexibleApiHandler> = {};

  for (const [method, handler] of Object.entries(handlers)) {
    if (handler) {
      wrappedHandlers[method] = withErrorHandler(handler as FlexibleApiHandler);
    }
  }

  return wrappedHandlers as {
    GET?: FlexibleApiHandler;
    POST?: FlexibleApiHandler;
    PUT?: FlexibleApiHandler;
    PATCH?: FlexibleApiHandler;
    DELETE?: FlexibleApiHandler;
  };
}

// ============== 条件错误处理 ==============

/**
 * 条件性地抛出错误
 * @param condition - 条件
 * @param errorCode - 错误码
 * @param message - 错误消息
 * @param details - 错误详情
 */
export function assertCondition(
  condition: boolean,
  errorCode: ErrorCodeType,
  message?: string,
  details?: unknown
): asserts condition {
  if (!condition) {
    throw new ApiError(errorCode, message, details);
  }
}

/**
 * 如果值为 null/undefined 则抛出错误
 * @param value - 要检查的值
 * @param message - 错误消息
 * @param errorCode - 错误码（默认 NOT_FOUND）
 */
export function assertExists<T>(
  value: T | null | undefined,
  message?: string,
  errorCode: ErrorCodeType = ErrorCode.NOT_FOUND
): asserts value is T {
  if (value === null || value === undefined) {
    throw new ApiError(errorCode, message);
  }
}

/**
 * 断言用户已登录
 * @param user - 当前用户
 * @param message - 错误消息
 */
export function assertAuthenticated(
  user: string | null | undefined,
  message = "请先登录"
): asserts user is string {
  if (!user) {
    throw ApiError.unauthorized(message);
  }
}

/**
 * 断言用户有权限执行操作
 * @param condition - 权限条件
 * @param message - 错误消息
 */
export function assertAuthorized(
  condition: boolean,
  message = "权限不足"
): void {
  if (!condition) {
    throw ApiError.forbidden(message);
  }
}

// ============== 资源操作辅助 ==============

/**
 * 获取资源或抛出 404
 * @param getter - 获取资源的函数
 * @param resourceName - 资源名称（用于错误消息）
 * @returns 资源
 * @throws ApiError (NOT_FOUND)
 */
export async function getOrThrow<T>(
  getter: () => Promise<T | null | undefined> | T | null | undefined,
  resourceName = "资源"
): Promise<T> {
  const result = await getter();
  
  if (result === null || result === undefined) {
    throw new ApiError(
      ErrorCode.NOT_FOUND,
      `${resourceName}不存在`
    );
  }
  
  return result;
}

// ============== 数据库错误处理 ==============

/**
 * 处理 Better-SQLite3 错误
 * @param error - 数据库错误
 * @returns ApiError
 */
export function handleDatabaseError(error: unknown): ApiError {
  if (error instanceof Error) {
    // 处理唯一约束冲突
    if (error.message.includes("UNIQUE constraint failed")) {
      const field = error.message.match(/UNIQUE constraint failed: (\w+)\.(\w+)/);
      return ApiError.conflict(
        "资源已存在",
        field ? { field: field[2] } : undefined
      );
    }
    
    // 处理外键约束
    if (error.message.includes("FOREIGN KEY constraint failed")) {
      return ApiError.badRequest("关联的资源不存在");
    }
    
    // 处理 NOT NULL 约束
    if (error.message.includes("NOT NULL constraint failed")) {
      const field = error.message.match(/NOT NULL constraint failed: (\w+)\.(\w+)/);
      return ApiError.validation(
        "必填字段不能为空",
        field ? { field: field[2] } : undefined
      );
    }
    
    console.error("Database Error:", error);
    return ApiError.internal("数据库操作失败");
  }
  
  return ApiError.internal("未知错误");
}

/**
 * 包装数据库操作，自动处理常见错误
 * @param operation - 数据库操作函数
 * @returns 操作结果
 */
export async function withDbHandler<T>(operation: () => Promise<T>): Promise<T> {
  try {
    return await operation();
  } catch (error) {
    throw handleDatabaseError(error);
  }
}

// ============== Next.js 兼容层 ==============

/**
 * 创建 Next.js 中间件（Edge Runtime）
 * 
 * 注意：这只适用于 middleware.ts 文件，用于处理全局中间件
 * 
 * 使用示例：
 * ```typescript
 * // middleware.ts
 * import { createErrorMiddleware } from "@/middleware/error-handler";
 * 
 * export default createErrorMiddleware({
 *   // 自定义错误处理逻辑
 *   onError: (error, req) => {
 *     console.error(`Error in ${req.url}:`, error);
 *   }
 * });
 * ```
 */
export interface ErrorMiddlewareOptions {
  onError?: (error: unknown, req: NextRequest) => void;
  includeStack?: boolean;
}

export function createErrorMiddleware(options: ErrorMiddlewareOptions = {}) {
  return async function errorMiddleware(req: NextRequest) {
    try {
      // 这里可以添加前置处理逻辑
      // 注意：Next.js 中间件无法直接包装 API Routes
      // 需要使用 withErrorHandler 包装每个 API Route
      
      return NextResponse.next();
    } catch (error) {
      options.onError?.(error, req);
      
      if (isApiError(error)) {
        return apiErrorResponse(error);
      }
      
      return errorResponse(
        ErrorCode.INTERNAL_ERROR,
        options.includeStack && error instanceof Error
          ? error.message
          : undefined
      );
    }
  };
}

