/**
 * 博客相关类型定义
 * Blog-related type definitions
 */

import type { UserRow } from './user';

// ============ 数据库实体类型 ============

/**
 * 文章状态
 * Post status
 */
export type PostStatus = 'published' | 'draft' | 'deleted';

/**
 * 数据库文章实体
 * Database Post Entity
 */
export interface Post {
  id: number;
  title: string;
  slug: string;
  content: string;
  created_at: string;
  updated_at: string;
  author: string;
  tags: string | null;
  status: PostStatus;
  category_id: number | null;
  view_count: number;
}

/**
 * 分类实体
 * Category entity
 */
export interface Category {
  id: number;
  name: string;
  slug: string;
  description: string;
  sort_order: number;
  is_active: number;
  created_at: string;
  updated_at: string;
  post_count?: number;
}

/**
 * 评论实体
 * Comment entity
 */
export interface Comment {
  id: number;
  post_id: number;
  author: string;
  content: string;
  created_at: string;
  parent_id: number | null;
  ip_address: string | null;
  like_count?: number;
  dislike_count?: number;
  author_name?: string;
  author_avatar?: string;
}

/**
 * 点赞实体
 * Like entity
 */
export interface Like {
  id: number;
  post_id: number;
  username: string;
  created_at: string;
}

/**
 * 踩实体
 * Dislike entity
 */
export interface Dislike {
  id: number;
  post_id: number;
  username: string;
  created_at: string;
}

/**
 * 评论投票实体
 * Comment vote entity
 */
export interface CommentVote {
  id: number;
  comment_id: number;
  username: string;
  value: 1 | -1;
  created_at: string;
}

/**
 * 收藏实体
 * Favorite entity
 */
export interface Favorite {
  id: number;
  post_id: number;
  username: string;
  created_at: string;
}

/**
 * 友链实体
 * Friend link entity
 */
export interface FriendLink {
  id: number;
  name: string;
  url: string;
  description: string | null;
  avatar_url: string | null;
  sort_order: number;
  is_active: number;
  created_at: string;
  updated_at: string;
}

// ============ 列表/展示类型 ============

/**
 * 文章列表项（包含统计信息）
 * Post list item with statistics
 */
export interface PostListItem {
  title: string;
  slug: string;
  content: string;
  created_at: string;
  author: string;
  tags: string | null;
  category_id: number | null;
  view_count: number;
  category_name: string | null;
  category_slug: string | null;
  like_count: number;
  dislike_count: number;
  comment_count: number;
  favorite_count: number;
  favorited_by_me: boolean;
  author_name: string;
  author_avatar: string;
}

/**
 * 文章详情（包含用户交互状态）
 * Post detail with user interaction status
 */
export interface PostDetail extends Post {
  category_name: string | null;
  category_slug: string | null;
  like_count: number;
  dislike_count: number;
  comment_count: number;
  favorite_count: number;
  liked_by_me: boolean;
  favorited_by_me: boolean;
  author_name: string;
  author_avatar: string;
}

/**
 * 文章列表响应
 * Post list response
 */
export interface PostListResponse {
  items: PostListItem[];
  total: number;
  page: number;
  size: number;
}

/**
 * 收藏列表响应
 * Favorites list response
 */
export interface FavoritesListResponse {
  items: PostListItem[];
  total: number;
  page: number;
  size: number;
}

/**
 * 评论列表项（包含作者信息）
 * Comment list item with author info
 */
export interface CommentListItem extends Comment {
  like_count: number;
  dislike_count: number;
  author_name: string;
  author_avatar: string;
}

/**
 * 活动项类型
 * Activity item type
 */
export type ActivityType = 'post' | 'like' | 'comment';

/**
 * 用户活动项
 * User activity item
 */
export interface ActivityItem {
  type: ActivityType;
  title: string;
  slug: string;
  created_at: string;
  content?: string;
  target_user?: string;
}

/**
 * 用户活动响应
 * User activities response
 */
export interface ActivitiesResponse {
  items: ActivityItem[];
  total: number;
}

/**
 * 通知项
 * Notification item
 */
export interface NotificationItem {
  sender: string;
  sender_nickname: string;
  sender_avatar: string;
  content: string;
  created_at: string;
  post_title: string;
  post_slug: string;
}

// ============ API 请求/响应类型 ============

/**
 * 创建文章请求
 * Create post request
 */
export interface CreatePostRequest {
  title: string;
  slug?: string;
  content: string;
  tags?: string;
  category_id?: number | null;
}

/**
 * 更新文章请求
 * Update post request
 */
export interface UpdatePostRequest {
  title: string;
  content: string;
  tags: string;
  category_id?: number | null;
}

/**
 * 添加评论请求
 * Add comment request
 */
export interface AddCommentRequest {
  content: string;
  parent_id?: number | null;
}

/**
 * 点赞/踩响应
 * Like/dislike response
 */
export interface ToggleLikeResponse {
  ok: boolean;
  liked?: boolean;
  disliked?: boolean;
  error?: string;
}

/**
 * 收藏响应
 * Favorite response
 */
export interface ToggleFavoriteResponse {
  ok: boolean;
  favorited?: boolean;
  error?: string;
}

/**
 * 评论投票请求
 * Comment vote request
 */
export interface VoteCommentRequest {
  value: 1 | -1;
}

/**
 * 更新评论请求
 * Update comment request
 */
export interface UpdateCommentRequest {
  content: string;
}

/**
 * 操作响应
 * Operation response
 */
export interface OperationResponse {
  ok: boolean;
  error?: string;
}

/**
 * 分类排序请求
 * Category reorder request
 */
export interface ReorderCategoriesRequest {
  ids: number[];
}

/**
 * 创建/更新分类请求
 * Create/update category request
 */
export interface CategoryRequest {
  name: string;
  slug: string;
  description?: string;
  sort_order?: number;
  is_active?: boolean;
}

/**
 * 创建/更新友链请求
 * Create/update friend link request
 */
export interface FriendLinkRequest {
  name: string;
  url: string;
  description?: string;
  avatar_url?: string;
  sort_order?: number;
  is_active?: boolean;
}

// ============ 组件 Props 类型 ============

/**
 * 文章卡片组件 Props
 * Post card component props
 */
export interface PostCardProps {
  post: PostListItem;
  showActions?: boolean;
  compact?: boolean;
}

/**
 * 评论组件 Props
 * Comment component props
 */
export interface CommentProps {
  comment: CommentListItem;
  currentUser?: string | null;
  onReply?: (commentId: number) => void;
  onVote?: (commentId: number, value: 1 | -1) => void;
}

/**
 * 分页组件 Props
 * Pagination props
 */
export interface PaginationProps {
  page: number;
  size: number;
  total: number;
  onPageChange: (page: number) => void;
}

/**
 * 文章过滤器
 * Post filters
 */
export interface PostFilters {
  query?: string;
  author?: string;
  tag?: string;
  category?: string;
}

export function getThumbnailUrl(originalUrl: string, width = 480) {
  if (!originalUrl) return "";
  if (originalUrl.startsWith("/uploads/")) {
    return originalUrl;
  }
  return originalUrl;
}
